// Auto-generated full lesson translations (inner HTML per pane) for hi.
window.LESSON_HTML = window.LESSON_HTML || {};
window.LESSON_HTML.hi = {"day-pane-1":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-leaf\" style=\"color: var(--accent-pink);\"></i> दिन 1: Hiragana की नींव\n                                    <span class=\"badge\">ध्वनिविज्ञान</span>\n                                </div>\n                                <p>इस खेल में आपका स्वागत है। जापानी भाषा में तीन लेखन प्रणालियाँ इस्तेमाल होती हैं: <strong>Hiragana</strong> (मूल जापानी शब्दों के लिए ध्वन्यात्मक अक्षर), <strong>Katakana</strong> (विदेशी शब्दों के लिए ध्वन्यात्मक अक्षर), और <strong>Kanji</strong> (चीनी अक्षर जो पूरे शब्दों या भावों को दर्शाते हैं)। आज का दिन पूरी तरह Hiragana के लिए है।</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">पाँच मूल स्वर (a, i, u, e, o)</div>\n                                    <p>लगभग हर जापानी ध्वनि में इनमें से कोई एक स्वर होता है — अपवाद हैं ん (n) और छोटा っ ठहराव। इन्हें इस तरह बोलें:</p>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>あ (a)</strong> - \"ah\" जैसे father में <button class=\"speak-btn\" data-speak=\"あ\"><i class=\"fa-solid fa-volume-high\"></i> चलाएँ</button></li>\n                                        <li><strong>い (i)</strong> - \"ee\" जैसे feet में <button class=\"speak-btn\" data-speak=\"い\"><i class=\"fa-solid fa-volume-high\"></i> चलाएँ</button></li>\n                                        <li><strong>う (u)</strong> - \"oo\" जैसे boot में <button class=\"speak-btn\" data-speak=\"う\"><i class=\"fa-solid fa-volume-high\"></i> चलाएँ</button></li>\n                                        <li><strong>え (e)</strong> - \"eh\" जैसे red में <button class=\"speak-btn\" data-speak=\"え\"><i class=\"fa-solid fa-volume-high\"></i> चलाएँ</button></li>\n                                        <li><strong>お (o)</strong> - \"oh\" जैसे boat में <button class=\"speak-btn\" data-speak=\"お\"><i class=\"fa-solid fa-volume-high\"></i> चलाएँ</button></li>\n                                    </ul>\n                                </div>\n\n                                <h3 style=\"margin: 20px 0 10px 0; color: #fff;\">व्यंजन समूहन प्रणाली</h3>\n                                <p>बाकी सभी अक्षर व्यंजनों (K, S, T, N, H, M, Y, R, W) को मूल स्वरों के साथ जोड़कर बनते हैं। उदाहरण के लिए, K-पंक्ति (K-row) है: <strong>か (ka), き (ki), く (ku), け (ke), こ (ko)</strong>।</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">दिन 1 का लक्ष्य</div>\n                                    <p>पूरी Hiragana ग्रिड देखने और उनकी ध्वनियों का अभ्यास करने के लिए <a href=\"#\" data-goto-tab=\"kana\">काना चार्ट्स</a> टैब पर जाएँ। फिर, अक्षर लिखने का अभ्यास करने के लिए <a href=\"#\" data-goto-tab=\"canvas\">कैनवस राइटर</a> टैब पर जाएँ। सहज महसूस होने पर, Hiragana कठिनाई स्तर में <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट एरिना</a> टैब में अपने ज्ञान की परीक्षा लें!</p>\n                                </div>\n                            </div>","day-pane-2":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-bolt\" style=\"color: var(--accent-pink);\"></i> दिन 2: Katakana और ध्वनि परिवर्तक चिह्न\n                                    <span class=\"badge\">ध्वनिविज्ञान भाग २</span>\n                                </div>\n                                <p>आज आप <strong>Katakana</strong> सीखेंगे, साथ ही वे चिह्न भी जो मूल ध्वनियों को घोष (voiced) और संयुक्त ध्वनियों में बदल देते हैं।</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. Katakana (カタカナ)</div>\n                                    <p>Katakana बिल्कुल वही ध्वनियाँ दर्शाता है जो Hiragana दर्शाता है, लेकिन इसमें तीखे, सीधे स्ट्रोक इस्तेमाल होते हैं। इसका उपयोग विदेशी नामों, स्थानों और उधार के शब्दों (loanwords) के लिए होता है (जैसे, カメラ - kamera, यानी camera के लिए)।</p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. Dakuon और Handakuon (ध्वनि में परिवर्तन)</div>\n                                    <p>किसी hiragana या katakana अक्षर के ऊपरी दाएँ भाग में उद्धरण-चिह्न जैसे निशान (dakuten <strong>゛</strong>) या छोटे वृत्त (handakuten <strong>゜</strong>) जोड़कर, आप व्यंजन ध्वनि बदल सकते हैं:</p>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>K-पंक्ति (K-row)</strong> (か) + ゛ = <strong>G-पंक्ति (G-row)</strong> (が - ga)</li>\n                                        <li><strong>S-पंक्ति (S-row)</strong> (さ) + ゛ = <strong>Z-पंक्ति (Z-row)</strong> (ざ - za)</li>\n                                        <li><strong>T-पंक्ति (T-row)</strong> (た) + ゛ = <strong>D-पंक्ति (D-row)</strong> (だ - da)</li>\n                                        <li><strong>H-पंक्ति (H-row)</strong> (は) + ゛ = <strong>B-पंक्ति (B-row)</strong> (ば - ba)</li>\n                                        <li><strong>H-पंक्ति (H-row)</strong> (は) + ゜ = <strong>P-पंक्ति (P-row)</strong> (ぱ - pa)</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. Yōon (संयुक्त ध्वनियाँ) और Sokuon (द्वित्व व्यंजन)</div>\n                                    <p>हम 'i' स्तंभ (column) के Hiragana (ki, shi, chi, आदि) को <strong>ゃ (ya)</strong>, <strong>ゅ (yu)</strong>, <strong>ょ (yo)</strong> के छोटे रूपों के साथ जोड़कर <strong>きゃ (kya)</strong> या <strong>しゅ (shu)</strong> जैसी ध्वनियाँ बनाते हैं।</p>\n                                    <p>एक छोटा <strong>っ (tsu)</strong> बोलते समय एक संक्षिप्त द्वित्व व्यंजन ठहराव पैदा करता है (जैसे, さっき - sakki: थोड़ी देर पहले)।</p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>इन ध्वनियों का अभ्यास <a href=\"#\" data-goto-tab=\"kana\">काना चार्ट्स</a> में करें, फिर उन्हें <a href=\"#\" data-goto-tab=\"canvas\">कैनवस राइटर</a> पर हाथ से लिखकर ट्रेस करें।</p>\n                                </div>\n                            </div>","day-pane-3":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-arrow-up-9-1\" style=\"color: var(--accent-pink);\"></i> दिन 3: संख्याएँ और Kanji परिचय\n                                    <span class=\"badge\">शब्दावली</span>\n                                </div>\n                                <p>बधाई हो, अब आप ध्वन्यात्मक रूप से तैयार हैं! अब असली शब्दावली की ओर चलते हैं। हम 1 से 100 तक की संख्याएँ सीखेंगे और अपने पहले Kanji अक्षरों से परिचय करेंगे।</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1 से 10 तक की संख्याएँ</div>\n                                    <table class=\"grammar-table\">\n                                        <thead>\n                                            <tr>\n                                                <th>संख्या</th>\n                                                <th>Hiragana</th>\n                                                <th>Romaji</th>\n                                                <th>Kanji</th>\n                                                <th>ऑडियो</th>\n                                            </tr>\n                                        </thead>\n                                        <tbody>\n                                            <tr><td>1</td><td><span class=\"ja-word\">いち</span></td><td>ichi</td><td>一</td><td><button class=\"speak-btn\" data-speak=\"いち\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>2</td><td><span class=\"ja-word\">に</span></td><td>ni</td><td>二</td><td><button class=\"speak-btn\" data-speak=\"に\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>3</td><td><span class=\"ja-word\">さん</span></td><td>san</td><td>三</td><td><button class=\"speak-btn\" data-speak=\"さん\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>4</td><td><span class=\"ja-word\">よん / し</span></td><td>yon / shi</td><td>四</td><td><button class=\"speak-btn\" data-speak=\"よん\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>5</td><td><span class=\"ja-word\">ご</span></td><td>go</td><td>五</td><td><button class=\"speak-btn\" data-speak=\"ご\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>6</td><td><span class=\"ja-word\">ろく</span></td><td>roku</td><td>六</td><td><button class=\"speak-btn\" data-speak=\"ろく\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>7</td><td><span class=\"ja-word\">なな / しち</span></td><td>nana / shichi</td><td>七</td><td><button class=\"speak-btn\" data-speak=\"なな\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>8</td><td><span class=\"ja-word\">はち</span></td><td>hachi</td><td>八</td><td><button class=\"speak-btn\" data-speak=\"はち\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>9</td><td><span class=\"ja-word\">きゅう / く</span></td><td>kyuu / ku</td><td>九</td><td><button class=\"speak-btn\" data-speak=\"きゅう\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>10</td><td><span class=\"ja-word\">じゅう</span></td><td>juu</td><td>十</td><td><button class=\"speak-btn\" data-speak=\"じゅう\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top: 10px;\"><strong>99 तक गिनती करना गणितीय है:</strong></p>\n                                    <ul class=\"bullet-list\">\n                                        <li>11 = दस + एक = じゅういち (juu-ichi)</li>\n                                        <li>20 = दो + दस = にじゅう (ni-juu)</li>\n                                        <li>45 = चार + दस + पाँच = よんじゅうご (yon-juu-go)</li>\n                                        <li>100 है <strong>ひゃく (hyaku)</strong></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">10 आवश्यक Kanji अक्षर</div>\n                                    <p>Kanji पूरे शब्दों या भावों को दर्शाते हैं। इन चित्रलिपियों को सीखें:</p>\n                                    <table class=\"grammar-table\">\n                                        <thead>\n                                            <tr>\n                                                <th>Kanji</th>\n                                                <th>अर्थ</th>\n                                                <th>उच्चारण</th>\n                                            </tr>\n                                        </thead>\n                                        <tbody>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">日</span></td><td>सूर्य / दिन</td><td>hi / nichi</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">月</span></td><td>चाँद / महीना</td><td>tsuki / getsu</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">火</span></td><td>आग</td><td>hi / ka</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">水</span></td><td>पानी</td><td>mizu / sui</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">木</span></td><td>पेड़ / लकड़ी</td><td>ki / moku</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">金</span></td><td>सोना / पैसा</td><td>kane / kin</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">土</span></td><td>पृथ्वी / मिट्टी</td><td>tsuchi / do</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">山</span></td><td>पर्वत</td><td>yama / san</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">川</span></td><td>नदी</td><td>kawa</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">人</span></td><td>व्यक्ति</td><td>hito / jin</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>इन संख्याओं और kanji की परीक्षा <a href=\"#\" data-goto-tab=\"flashcards\">फ़्लैशकार्ड्स</a> से लें, फिर उन्हें <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट एरिना</a> में इस्तेमाल करें।</p>\n                                </div>\n                            </div>","day-pane-4":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-puzzle-piece\" style=\"color: var(--accent-pink);\"></i> दिन 4: कण (Particles) और वाक्य संरचना\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>अब बात करते हैं कि वाक्य कैसे बनते हैं। अंग्रेज़ी की संरचना है कर्ता-क्रिया-कर्म / Subject-Verb-Object (\"I eat sushi\")। जापानी की संरचना है <strong>कर्ता-कर्म-क्रिया / Subject-Object-Verb</strong> (\"I sushi eat\")।</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. शब्द-क्रम संरचना (Word Order Structure)</div>\n                                    <p>अंग्रेज़ी: <em>I read books.</em></p>\n                                    <p>जापानी: <em>わたしは ほんを よみます (Watashi wa hon o yomimasu)</em> &rarr; <strong>मैं [विषय] किताब [कर्म] पढ़ना।</strong></p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. महत्वपूर्ण कण (助詞)</div>\n                                    <p>कण (particles) वे छोटे शब्द हैं जो संज्ञाओं (nouns) के बाद जोड़े जाते हैं ताकि उनकी व्याकरणिक भूमिका दिखाई जा सके:</p>\n                                    <table class=\"grammar-table\">\n                                        <thead>\n                                            <tr>\n                                                <th>कण (Particle)</th>\n                                                <th>कार्य (Function)</th>\n                                                <th>उदाहरण (Example)</th>\n                                            </tr>\n                                        </thead>\n                                        <tbody>\n                                            <tr>\n                                                <td><span class=\"ja-word\">は (wa)</span></td>\n                                                <td>वाक्य के मुख्य <strong>विषय (topic)</strong> को चिह्नित करता है। (लिखा जाता है \"ha\" पर बोला जाता है \"wa\"।)</td>\n                                                <td>わたし<strong>は</strong>... (watashi wa... — जहाँ तक मेरी बात है...)</td>\n                                            </tr>\n                                            <tr>\n                                                <td><span class=\"ja-word\">を (o)</span></td>\n                                                <td>क्रिया से प्रभावित होने वाले <strong>प्रत्यक्ष कर्म (direct object)</strong> को चिह्नित करता है। (लिखा जाता है \"wo\" पर बोला जाता है \"o\"।)</td>\n                                                <td>ほん<strong>を</strong>よむ (hon o yomu — किताब पढ़ना)</td>\n                                            </tr>\n                                            <tr>\n                                                <td><span class=\"ja-word\">に (ni)</span></td>\n                                                <td><strong>समय (time)</strong> या <strong>गंतव्य (destination)</strong> (to/at) को चिह्नित करता है।</td>\n                                                <td>にほん<strong>に</strong>いく (nihon ni iku — जापान जाना)</td>\n                                            </tr>\n                                            <tr>\n                                                <td><span class=\"ja-word\">で (de)</span></td>\n                                                <td>किसी क्रिया के होने का <strong>स्थान (location)</strong>, या इस्तेमाल होने वाला <strong>साधन (tool)</strong> (by/at) दिखाता है।</td>\n                                                <td>レストラン<strong>で</strong>たべる (resutoran de taberu — रेस्टोरां में खाना)</td>\n                                            </tr>\n                                            <tr>\n                                                <td><span class=\"ja-word\">の (no)</span></td>\n                                                <td><strong>स्वामित्व (possession)</strong> दिखाता है (अंग्रेज़ी के apostrophe-s जैसा)।</td>\n                                                <td>わたし<strong>の</strong>ねこ (watashi no neko — मेरी बिल्ली)</td>\n                                            </tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>इन कणों (particles) को <a href=\"#\" data-goto-tab=\"builder\">सेंटेंस बिल्डर</a> में सही जगह पर बिठाएँ, या <a href=\"#\" data-goto-tab=\"bridge\">ट्राइलिंगुअल ब्रिज</a> में देखें कि ये अलग-अलग भाषाओं में कैसे मेल खाते हैं।</p>\n                                </div>\n                            </div>","day-pane-5":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-code-commit\" style=\"color: var(--accent-pink);\"></i> दिन 5: क्रियाएँ और क्रिया-रूपांतरण (Conjugation)\n                                    <span class=\"badge\">व्याकरण भाग २</span>\n                                </div>\n                                <p>आज हम जापानी क्रियाएँ (verbs) सीखेंगे और यह भी कि उन्हें औपचारिक विनम्र (formal polite) स्तर में कैसे रूपांतरित किया जाता है। जापानी क्रिया-रूपांतरण बेहद नियमित है - कर्ता व्यक्ति (I, you, they) के अनुसार कोई बदलाव नहीं होता, सबका रूपांतरण बिल्कुल एक जैसा होता है!</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. क्रिया समूह (Verb Groups)</div>\n                                    <p>सभी जापानी क्रियाएँ अपने शब्दकोश (dictionary/base) रूप में 'u' ध्वनि पर समाप्त होती हैं। वे तीन समूहों में बँटती हैं:</p>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>Ru-verbs (समूह 2)</strong>: -iru या -eru पर समाप्त होती हैं। (जैसे, たべる - taberu: खाना, みる - miru: देखना)।</li>\n                                        <li><strong>U-verbs (समूह 1)</strong>: बाकी -u ध्वनियों पर समाप्त होती हैं। (जैसे, のむ - nomu: पीना, いく - iku: जाना, はなす - hanasu: बोलना)।</li>\n                                        <li><strong>ध्यान दें:</strong> हर -iru/-eru क्रिया ru-verb नहीं होती — कुछ गिनी-चुनी क्रियाएँ असल में u-verbs हैं जिन्हें आपको बस याद रखना होगा: かえる (kaeru — लौटना), はしる (hashiru — दौड़ना), はいる (hairu — अंदर जाना), きる (kiru — काटना), いる (iru — ज़रूरत होना)।</li>\n                                        <li><strong>अनियमित क्रियाएँ (Irregular Verbs, समूह 3)</strong>: सिर्फ़ दो! <strong>する (suru: करना)</strong> और <strong>くる (kuru: आना)</strong>।</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. विनम्र (~masu) रूप का रूपांतरण</div>\n                                    <p>विनम्रता से बात करने के लिए, क्रियाओं को <strong>~ます (~masu)</strong> प्रत्यय में बदलें। रूपांतरण के सूत्र:</p>\n                                    <table class=\"grammar-table\">\n                                        <thead>\n                                            <tr>\n                                                <th>समूह (Group)</th>\n                                                <th>शब्दकोश रूप (Dictionary Form)</th>\n                                                <th>विनम्र रूप - सकारात्मक (Polite Form)</th>\n                                                <th>विनम्र रूप - नकारात्मक (Polite Form)</th>\n                                            </tr>\n                                        </thead>\n                                        <tbody>\n                                            <tr>\n                                                <td><strong>Ru-verbs</strong> (-ru हटाएँ, -masu जोड़ें)</td>\n                                                <td>たべる (taberu)</td>\n                                                <td><span class=\"ja-word\">たべます</span> (tabemasu)</td>\n                                                <td><span class=\"ja-word\">たべません</span> (tabemasen)</td>\n                                            </tr>\n                                            <tr>\n                                                <td><strong>U-verbs</strong> ('u' स्वर को 'i' में बदलें, -masu जोड़ें)</td>\n                                                <td>のむ (nomu)</td>\n                                                <td><span class=\"ja-word\">のみます</span> (nomimasu)</td>\n                                                <td><span class=\"ja-word\">のみません</span> (nomimasen)</td>\n                                            </tr>\n                                            <tr>\n                                                <td><strong>अनियमित (Irregulars)</strong> (निश्चित परिवर्तन)</td>\n                                                <td>する (suru) / くる (kuru)</td>\n                                                <td><span class=\"ja-word\">します</span> / <span class=\"ja-word\">きます</span></td>\n                                                <td><span class=\"ja-word\">しません</span> / <span class=\"ja-word\">きません</span></td>\n                                            </tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. भूतकाल विनम्र रूप (Past Tense Polite)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>भूतकाल सकारात्मक (Past Affirmative): <strong>~ます</strong> को <strong>~ました (~mashita)</strong> से बदलें। जैसे, たべました (tabemashita — मैंने खाया)।</li>\n                                        <li>भूतकाल नकारात्मक (Past Negative): <strong>~ます</strong> को <strong>~ませんでした (~masendeshita)</strong> से बदलें। जैसे, たべませんでした (tabemasendeshita — मैंने नहीं खाया)।</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>इन रूपांतरणों (conjugations) को <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट एरिना</a> में इस्तेमाल करें, फिर <a href=\"#\" data-goto-tab=\"flashcards\">फ़्लैशकार्ड्स</a> से शब्दावली को मज़बूत करें।</p>\n                                </div>\n                            </div>","day-pane-6":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-heart\" style=\"color: var(--accent-pink);\"></i> दिन 6: विशेषण (Adjectives) और व्यावहारिक वाक्यांश\n                                    <span class=\"badge\">बातचीत</span>\n                                </div>\n                                <p>आज हम जापानी विशेषणों (adjectives) से चीज़ों का वर्णन करना सीखेंगे, और जापान में यात्रा करने, खाना खाने और घूमने के लिए ज़रूरी वाक्यांश इकट्ठा करेंगे।</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. विशेषणों के दो प्रकार</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>I-विशेषण (I-adjectives)</strong>: hiragana い (i) पर समाप्त होते हैं। उदाहरण के लिए おいしい (oishii: स्वादिष्ट) या おおきい (ookii: बड़ा)। ये संज्ञा के ठीक पहले सीधे आते हैं: おいしいすし (स्वादिष्ट sushi)।</li>\n                                        <li><strong>Na-विशेषण (Na-adjectives)</strong>: जिस संज्ञा का वर्णन करते हैं उसके पहले な (na) चाहिए होता है। उदाहरण के लिए しずか (shizuka: शांत) &rarr; しずかな部屋 (shizuka na heya: एक शांत कमरा)।</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. सबसे ज़रूरी व्यावहारिक वाक्यांश (Survival Phrases)</div>\n                                    <table class=\"grammar-table\">\n                                        <thead>\n                                            <tr>\n                                                <th>अंग्रेज़ी (English)</th>\n                                                <th>जापानी (Hiragana / Kanji)</th>\n                                                <th>Romaji</th>\n                                                <th>ऑडियो</th>\n                                            </tr>\n                                        </thead>\n                                        <tbody>\n                                            <tr><td>नमस्ते / शुभ दोपहर</td><td><span class=\"ja-word\">こんにちは</span></td><td>Konnichiwa</td><td><button class=\"speak-btn\" data-speak=\"こんにちは\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>धन्यवाद (विनम्र)</td><td><span class=\"ja-word\">ありがとうございます</span></td><td>Arigatou gozaimasu</td><td><button class=\"speak-btn\" data-speak=\"ありがとうございます\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>माफ़ कीजिए / क्षमा करें</td><td><span class=\"ja-word\">すみません</span></td><td>Sumimasen</td><td><button class=\"speak-btn\" data-speak=\"すみません\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>बाथरूम कहाँ है?</td><td><span class=\"ja-word\">トイレはどこですか。</span></td><td>Toire wa doko desu ka?</td><td><button class=\"speak-btn\" data-speak=\"トイレはどこですか\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>कृपया मुझे पानी दीजिए।</td><td><span class=\"ja-word\">お水をください。</span></td><td>Omizu o kudasai</td><td><button class=\"speak-btn\" data-speak=\"お水をください\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>यह कितने का है?</td><td><span class=\"ja-word\">これはいくらですか。</span></td><td>Kore wa ikura desu ka?</td><td><button class=\"speak-btn\" data-speak=\"これはいくらですか\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>इन वाक्यांशों पर <a href=\"#\" data-goto-tab=\"flashcards\">फ़्लैशकार्ड्स</a> से खुद को परखें, फिर <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट एरिना</a> में लाइव इनका सामना करें।</p>\n                                </div>\n                            </div>","day-pane-7":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-trophy\" style=\"color: var(--accent-pink);\"></i> दिन 7: वार्तालाप मास्टरक्लास\n                                    <span class=\"badge\">निपुणता</span>\n                                </div>\n                                <p>अंतिम दिन में आपका स्वागत है। आइए एक पूरा वार्तालाप परिदृश्य देखें, जो ध्वनिविज्ञान से लेकर क्रिया संरचना तक सब कुछ आपस में जोड़ता है।</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">रेस्टोरां परिदृश्य संवाद</div>\n                                    <p>नीचे दिए गए संवाद को पढ़ें और इसे बोला हुआ सुनने के लिए स्पीकर आइकन पर क्लिक करें:</p>\n\n                                    <p style=\"margin-top: 15px;\"><strong>ग्राहक:</strong></p>\n                                    <p style=\"padding-left: 10px;\"><span class=\"ja-word\" style=\"color: #fff;\">すみません、メニューをください。</span><br>\n                                    <em>Sumimasen, menyuu o kudasai.</em><br>\n                                    (माफ़ कीजिए, कृपया मुझे मेनू दीजिए।)\n                                    <button class=\"speak-btn\" data-speak=\"すみません、メニューをください。\"><i class=\"fa-solid fa-volume-high\"></i> चलाएँ</button></p>\n\n                                    <p style=\"margin-top: 15px;\"><strong>वेटर:</strong></p>\n                                    <p style=\"padding-left: 10px;\"><span class=\"ja-word\" style=\"color: #fff;\">はい、どうぞ。</span><br>\n                                    <em>Hai, douzo.</em><br>\n                                    (जी हाँ, लीजिए।)\n                                    <button class=\"speak-btn\" data-speak=\"はい、どうぞ。\"><i class=\"fa-solid fa-volume-high\"></i> चलाएँ</button></p>\n\n                                    <p style=\"margin-top: 15px;\"><strong>ग्राहक:</strong></p>\n                                    <p style=\"padding-left: 10px;\"><span class=\"ja-word\" style=\"color: #fff;\">これはいくらですか。</span><br>\n                                    <em>Kore wa ikura desu ka.</em><br>\n                                    (यह कितने का है?)\n                                    <button class=\"speak-btn\" data-speak=\"これはいくらですか。\"><i class=\"fa-solid fa-volume-high\"></i> चलाएँ</button></p>\n\n                                    <p style=\"margin-top: 15px;\"><strong>वेटर:</strong></p>\n                                    <p style=\"padding-left: 10px;\"><span class=\"ja-word\" style=\"color: #fff;\">それは千円です。</span><br>\n                                    <em>Sore wa sen en desu.</em><br>\n                                    (वह 1000 येन का है।)\n                                    <button class=\"speak-btn\" data-speak=\"それはせんえんです。\"><i class=\"fa-solid fa-volume-high\"></i> चलाएँ</button></p>\n\n                                    <p style=\"margin-top: 15px;\"><strong>ग्राहक:</strong></p>\n                                    <p style=\"padding-left: 10px;\"><span class=\"ja-word\" style=\"color: #fff;\">じゃあ、これをください。</span><br>\n                                    <em>Jaa, kore o kudasai.</em><br>\n                                    (तो फिर, कृपया मुझे यह दीजिए।)\n                                    <button class=\"speak-btn\" data-speak=\"じゃあ、これをください。\"><i class=\"fa-solid fa-volume-high\"></i> चलाएँ</button></p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"builder\">सेंटेंस बिल्डर</a> में अपना खुद का जवाब बनाएँ, फिर पूरे संवाद को <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट एरिना</a> में लाइव आज़माएँ।</p>\n                                </div>\n                            </div>","day-pane-8":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-link\" style=\"color: var(--accent-pink);\"></i> N4·1: ते-फ़ॉर्म (て形)\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p><strong>ते-फ़ॉर्म (て-रूप)</strong> जापानी व्याकरण की सबसे ज़रूरी कड़ी है — यह क्रियाओं को आपस में जोड़ता है और अनुरोध, अनुमति व निरंतर क्रिया (progressive) को संभव बनाता है। आइए देखें कि इसे कैसे बनाया जाता है और यह क्या-क्या काम करता है।</p>\n                                <p style=\"font-size:0.85rem;color:var(--text-muted);\">याद रखें: る-क्रियाएँ (Group 2) -iru/-eru पर खत्म होती हैं, जैसे たべる (taberu); う-क्रियाएँ (Group 1) बाकी सब हैं, जैसे のむ (nomu) — यह N5·5 में बताया जा चुका है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. इसे कैसे बनाएं</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>क्रिया का अंत</th><th>बदलाव</th><th>उदाहरण</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>る-क्रियाएँ</td><td>る → て</td><td>たべる → <span class=\"ja-word\">たべて</span> (taberu → tabete)</td></tr>\n                                            <tr><td>う・つ・る</td><td>→ って</td><td>かう → <span class=\"ja-word\">かって</span> (kau → katte)</td></tr>\n                                            <tr><td>む・ぶ・ぬ</td><td>→ んで</td><td>のむ → <span class=\"ja-word\">のんで</span> (nomu → nonde)</td></tr>\n                                            <tr><td>く</td><td>→ いて</td><td>かく → <span class=\"ja-word\">かいて</span> (kaku → kaite)</td></tr>\n                                            <tr><td>ぐ</td><td>→ いで</td><td>およぐ → <span class=\"ja-word\">およいで</span> (oyogu → oyoide)</td></tr>\n                                            <tr><td>す</td><td>→ して</td><td>はなす → <span class=\"ja-word\">はなして</span> (hanasu → hanashite)</td></tr>\n                                            <tr><td>अनियमित</td><td>—</td><td>する→<span class=\"ja-word\">して</span>, くる→<span class=\"ja-word\">きて</span> (suru → shite, kuru → kite)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top:8px;font-size:0.85rem;color:var(--text-muted);\">अपवाद: いく → <span class=\"ja-word\">いって</span> (iku → itte) (いいて नहीं)।</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. यह क्या करता है</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>अनुरोध:</strong> ～てください — <span class=\"ja-word\">みてください</span> (mite kudasai — देखिए) <button class=\"speak-btn\" data-speak=\"みてください\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong>अनुमति:</strong> ～てもいいです — <span class=\"ja-word\">たべてもいいです</span> (tabete mo ii desu — आप खा सकते हैं) <button class=\"speak-btn\" data-speak=\"たべてもいいです\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong>प्रगतिशील रूप / अवस्था:</strong> ～ています — <span class=\"ja-word\">よんでいます</span> (yonde imasu — पढ़ रहा/रही हूँ) <button class=\"speak-btn\" data-speak=\"よんでいます\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong>निषेध:</strong> ～てはいけません — <span class=\"ja-word\">はいってはいけません</span> (haitte wa ikemasen — अंदर जाना मना है)</li>\n                                        <li><strong>क्रियाओं को जोड़ना:</strong> <span class=\"ja-word\">おきて、たべて、いきます</span> (okite, tabete, ikimasu — मैं उठता हूँ, खाता हूँ, और जाता हूँ)</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>ते-फ़ॉर्म से जुड़े सवालों का डटकर सामना <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट अरीना</a> में कीजिए, फिर <a href=\"#\" data-goto-tab=\"builder\">वाक्य निर्माता</a> में अपने वाक्यों को आपस में जोड़ना सीखिए।</p>\n                                </div>\n                            </div>","day-pane-9":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-comments\" style=\"color: var(--accent-pink);\"></i> N4·2: सादा (कैज़ुअल) रूप\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>विनम्र ～ます रूप अजनबियों और औपचारिक मौकों के लिए है। दोस्तों और परिवार के साथ जापानी में <strong>सादा रूप (plain form)</strong> इस्तेमाल होता है — और ज़्यादातर उन्नत व्याकरण बनाने के लिए आपको यही चाहिए।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">वर्तमान काल: सादा बनाम विनम्र</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>अर्थ</th><th>विनम्र</th><th>सादा</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>खाना</td><td>たべます (tabemasu)</td><td><span class=\"ja-word\">たべる</span> (taberu)</td></tr>\n                                            <tr><td>न खाना</td><td>たべません (tabemasen)</td><td><span class=\"ja-word\">たべない</span> (tabenai)</td></tr>\n                                            <tr><td>पीना</td><td>のみます (nomimasu)</td><td><span class=\"ja-word\">のむ</span> (nomu)</td></tr>\n                                            <tr><td>न पीना</td><td>のみません (nomimasen)</td><td><span class=\"ja-word\">のまない</span> (nomanai)</td></tr>\n                                            <tr><td>है (चीज़ के लिए)</td><td>です (desu)</td><td><span class=\"ja-word\">だ</span> (da)</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">सादा नकारात्मक रूप (～ない)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>る-क्रियाएँ:</strong> る हटाएँ, ない जोड़ें — みる (miru — देखना) → <span class=\"ja-word\">みない</span> (minai)</li>\n                                        <li><strong>う-क्रियाएँ:</strong> अंतिम -u → -a + ない — のむ (nomu — पीना) → <span class=\"ja-word\">のまない</span> (nomanai) (う, わ में बदल जाता है: かう (kau — खरीदना) → かわない (kawanai))</li>\n                                        <li><strong>अनियमित:</strong> する (suru — करना) → <span class=\"ja-word\">しない</span> (shinai), くる (kuru — आना) → <span class=\"ja-word\">こない</span> (konai), ある (aru — होना/अस्तित्व में होना) → <span class=\"ja-word\">ない</span> (nai)</li>\n                                    </ul>\n                                    <p style=\"font-size:0.85rem;color:var(--text-muted);\">टिप: बोलचाल में です／か अक्सर छोड़ दिया जाता है — <span class=\"ja-word\">たべる？</span> (taberu?) (स्वर को ऊपर उठाकर बोलने पर) का मतलब है \"खाओगे?\"</p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट अरीना</a> में विनम्र और सादा रूपों के बीच अदला-बदली कीजिए, फिर <a href=\"#\" data-goto-tab=\"builder\">वाक्य निर्माता</a> में कैज़ुअल वाक्य बनाइए।</p>\n                                </div>\n                            </div>","day-pane-10":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-clock-rotate-left\" style=\"color: var(--accent-pink);\"></i> N4·3: सादा भूतकाल और नकारात्मक भूतकाल\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>सादा भूतकाल (<strong>た-रूप</strong>) बिल्कुल ते-फ़ॉर्म जैसे ही नियमों से बनता है — बस て/で की जगह た/だ लगा दें। यह बोलचाल की भाषा और ～たことがある (कर चुका होना) जैसी व्याकरण संरचनाओं का आधार है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">भूतकाल सकारात्मक रूप (～た)</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>समूह</th><th>नियम</th><th>उदाहरण</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>る-क्रियाएँ</td><td>る → た</td><td>たべる → <span class=\"ja-word\">たべた</span> (taberu → tabeta — खाना → खाया)</td></tr>\n                                            <tr><td>う・つ・る</td><td>→ った</td><td>かう → <span class=\"ja-word\">かった</span> (kau → katta — खरीदना → खरीदा)</td></tr>\n                                            <tr><td>む・ぶ・ぬ</td><td>→ んだ</td><td>のむ → <span class=\"ja-word\">のんだ</span> (nomu → nonda — पीना → पिया)</td></tr>\n                                            <tr><td>く / ぐ</td><td>→ いた / いだ</td><td>かく → <span class=\"ja-word\">かいた</span> (kaku → kaita — लिखना → लिखा)</td></tr>\n                                            <tr><td>す</td><td>→ した</td><td>はなす → <span class=\"ja-word\">はなした</span> (hanasu → hanashita — बोलना → बोला)</td></tr>\n                                            <tr><td>अनियमित</td><td>—</td><td>する→<span class=\"ja-word\">した</span>, くる→<span class=\"ja-word\">きた</span>, いく→<span class=\"ja-word\">いった</span> (suru → shita, kuru → kita, iku → itta — करना/आना/जाना → किया/आया/गया)</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">भूतकाल नकारात्मक रूप (～なかった)</div>\n                                    <p>सादा नकारात्मक रूप ～ない लें और उसके い को <strong>かった</strong> में बदल दें:</p>\n                                    <ul class=\"bullet-list\">\n                                        <li>たべない (tabenai) → <span class=\"ja-word\">たべなかった</span> (tabenakatta) (नहीं खाया) <button class=\"speak-btn\" data-speak=\"たべなかった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>いかない (ikanai) → <span class=\"ja-word\">いかなかった</span> (ikanakatta) (नहीं गया)</li>\n                                        <li>い-विशेषणों (i-adjectives) पर भी यही नियम लागू होता है: たかい → <span class=\"ja-word\">たかくなかった</span> (takai → takaku nakatta — महँगा → महँगा नहीं था)</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>भूतकाल के रूपों को <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट अरीना</a> में परखिए, फिर <a href=\"#\" data-goto-tab=\"builder\">वाक्य निर्माता</a> में भूतकाल के वाक्य बनाइए।</p>\n                                </div>\n                            </div>","day-pane-11":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-list-ol\" style=\"color: var(--accent-pink);\"></i> N4·4: काउंटर (助数詞)\n                                    <span class=\"badge\">शब्दावली</span>\n                                </div>\n                                <p>जापानी में अलग-अलग <em>प्रकार</em> की चीज़ों को गिनने के लिए अलग-अलग काउंटर शब्द इस्तेमाल होते हैं। अगर पक्का न पता हो, तो सामान्य <strong>つ</strong> काउंटर (1–10) लगभग हर चीज़ के लिए काम कर जाता है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">आम काउंटर</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>काउंटर</th><th>किसके लिए इस्तेमाल होता है</th><th>उदाहरण</th></tr></thead>\n                                        <tbody>\n                                            <tr><td><span class=\"ja-word\">～つ</span></td><td>सामान्य चीज़ें (1–10)</td><td>ひとつ (hitotsu), ふたつ (futatsu), みっつ (mittsu)…</td></tr>\n                                            <tr><td><span class=\"ja-word\">～こ (個)</span></td><td>छोटी चीज़ें</td><td>りんご3こ (ringo sanko — 3 सेब)</td></tr>\n                                            <tr><td><span class=\"ja-word\">～にん (人)</span></td><td>लोग</td><td>3にん (san-nin) (3 लोग)*</td></tr>\n                                            <tr><td><span class=\"ja-word\">～まい (枚)</span></td><td>चपटी चीज़ें (कागज़, टिकट)</td><td>きっぷ2まい (kippu nimai — 2 टिकट)</td></tr>\n                                            <tr><td><span class=\"ja-word\">～ほん (本)</span></td><td>लंबी चीज़ें (पेन, बोतलें)</td><td>ペン1ぽん (pen ippon — 1 पेन)</td></tr>\n                                            <tr><td><span class=\"ja-word\">～ひき (匹)</span></td><td>छोटे जानवर</td><td>ねこ2ひき (neko nihiki — 2 बिल्लियाँ)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"font-size:0.85rem;color:var(--text-muted);\">* लोगों को गिनने के नियम अनियमित हैं: 1人 <span class=\"ja-word\">ひとり</span> (hitori), 2人 <span class=\"ja-word\">ふたり</span> (futari), फिर 3人 さんにん (san-nin)… 本/匹 के साथ उच्चारण भी बदल जाता है (いっぽん ippon, さんぼん sanbon) — इन्हें सुन-सुनकर याद करना बेहतर है।</p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"flashcards\">फ्लैशकार्ड</a> से काउंटरों की खुद जाँच कीजिए, फिर <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट अरीना</a> में गिनते हुए आगे बढ़िए।</p>\n                                </div>\n                            </div>","day-pane-12":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-gift\" style=\"color: var(--accent-pink);\"></i> N4·5: देना और पाना\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>जापानी में सही क्रिया चुनना <strong>दिशा</strong> पर निर्भर करता है — कौन किसे दे रहा है। इन तीनों क्रियाओं को अच्छी तरह समझ लें, तो रोज़मर्रा की बहुत-सी बातचीत आसान हो जाती है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">ये तीन क्रियाएँ</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong class=\"ja-word\">あげる</strong> — मैं/कोई <em>बाहर की ओर</em> देता है। わたしは ともだち<strong>に</strong> プレゼントを あげる. (Watashi wa tomodachi ni purezento o ageru. — मैं अपने दोस्त को एक तोहफ़ा देता हूँ।) <button class=\"speak-btn\" data-speak=\"わたしはともだちにプレゼントをあげる\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong class=\"ja-word\">くれる</strong> — कोई <em>मुझे</em> देता है। ともだちが わたしに プレゼントを <strong>くれる</strong>. (Tomodachi ga watashi ni purezento o kureru. — मेरा दोस्त मुझे एक तोहफ़ा देता है।) <button class=\"speak-btn\" data-speak=\"ともだちがわたしにプレゼントをくれる\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong class=\"ja-word\">もらう</strong> — मैं <em>पाता हूँ</em> (देने वाले को に／から से चिह्नित किया जाता है)। わたしは ともだち<strong>に</strong> プレゼントを <strong>もらう</strong>. (Watashi wa tomodachi ni purezento o morau. — मुझे अपने दोस्त से एक तोहफ़ा मिलता है।) <button class=\"speak-btn\" data-speak=\"わたしはともだちにプレゼントをもらう\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                    <p style=\"font-size:0.85rem;color:var(--text-muted);\">आसान नियम: अगर तोहफ़ा <strong>आपकी ओर</strong> आ रहा है, तो वह くれる या もらう होगा — कभी あげる नहीं।</p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"builder\">वाक्य निर्माता</a> में देने-पाने के वाक्य बनाइए, फिर <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट अरीना</a> में सही क्रिया चुनने की परख कीजिए।</p>\n                                </div>\n                            </div>","day-pane-13":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-unlock\" style=\"color: var(--accent-pink);\"></i> N4·6: संभावना रूप (potential form) — \"कर सकना\"\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p><strong>संभावना रूप (potential form)</strong> का मतलब है \"कर सकना / में सक्षम होना।\" एक दिलचस्प मोड़: कर्म चिह्न (object particle) को अक्सर <strong>が</strong> में बदल दिया जाता है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">इसे कैसे बनाएं</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>समूह</th><th>नियम</th><th>उदाहरण</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>る-क्रियाएँ</td><td>る → られる</td><td>たべる (taberu) → <span class=\"ja-word\">たべられる</span> (taberareru) (खा सकना)</td></tr>\n                                            <tr><td>う-क्रियाएँ</td><td>-u → -eru</td><td>のむ → <span class=\"ja-word\">のめる</span> (nomeru) (पी सकना), かく → <span class=\"ja-word\">かける</span> (kakeru) (लिख सकना)</td></tr>\n                                            <tr><td>अनियमित</td><td>—</td><td>する → <span class=\"ja-word\">できる</span> (dekiru) (कर सकना), くる → <span class=\"ja-word\">こられる</span> (korareru) (आ सकना)</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">を → が में बदलाव</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>にほんご<strong>を</strong>はなす (nihongo o hanasu — जापानी बोलना) → にほんご<strong>が</strong>はなせる (nihongo ga hanaseru — जापानी बोल सकना) <button class=\"speak-btn\" data-speak=\"にほんごがはなせる\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>かんじ<strong>が</strong>よめる (kanji ga yomeru — कांजी पढ़ सकना)</li>\n                                        <li>बोलचाल में अक्सर ら को हटा दिया जाता है: たべられる (taberareru) → <span class=\"ja-word\">たべれる</span> (tabereru) (\"रा-रहित\" रूप)। यह ra-nuki (ら-नुकी) रोज़मर्रा की बोलचाल में आम है, लेकिन लेखन और परीक्षाओं में इसे अब भी अशुद्ध/अनौपचारिक ही माना जाता है।</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>अपने \"कर सकना\" वाले रूपों को <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट अरीना</a> में परखिए, फिर <a href=\"#\" data-goto-tab=\"builder\">वाक्य निर्माता</a> में उनसे वाक्य बनाइए।</p>\n                                </div>\n                            </div>","day-pane-14":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-code-branch\" style=\"color: var(--accent-pink);\"></i> N3·1: सशर्त वाक्य I (Conditionals I) — ～たら और ～と\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>N3 में \"अगर/जब\" कहने के चार तरीके खुलते हैं — <strong>～たら</strong>, <strong>～と</strong>, <strong>～ば</strong>, और <strong>～なら</strong>। यह पाठ पहले दो को कवर करता है: लचीला और सर्वउपयोगी ～たら, और स्वतः या नियमित परिणामों के लिए प्रयुक्त होने वाला ～と।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～たら और ～と बनाना</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>रूप</th><th>नियम</th><th>उदाहरण</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>～たら</td><td>सामान्य भूतकाल (た-form) + ら</td><td>のむ → のんだ → <span class=\"ja-word\">のんだら</span> (nomu → nonda → nondara — पीना → अगर/जब [आप] पीते हैं)</td></tr>\n                                            <tr><td>～たら (い-adj)</td><td>～かった + ら</td><td>たかい → <span class=\"ja-word\">たかかったら</span> (takai → takakattara — अगर [यह] महंगा है)</td></tr>\n                                            <tr><td>～と</td><td>सामान्य वर्तमानकाल (dictionary form) + と</td><td>まがる → <span class=\"ja-word\">まがると</span> (magaru → magaru to — अगर/जब [आप] मुड़ते हैं)</td></tr>\n                                            <tr><td>～と (संज्ञा/な-adj)</td><td>～だ + と</td><td>しずかだ → <span class=\"ja-word\">しずかだと</span> (shizuka da → shizuka da to — अगर [यह] शांत है)</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. たら लचीला है, と नहीं</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>～たら किसी भी मुख्य उपवाक्य की अनुमति देता है — अनुरोध, आमंत्रण, आदेश: いえにかえったら、でんわしてください (ie ni kaettara, denwa shite kudasai — जब आप घर पहुंचें, तो कृपया फोन करें) <button class=\"speak-btn\" data-speak=\"いえにかえったら、でんわしてください\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>～と स्वतः या सामान्य परिणामों का वर्णन करता है — मुख्य उपवाक्य अनुरोध, आदेश या आमंत्रण नहीं हो सकता: はるになると、さくらがさきます (haru ni naru to, sakura ga sakimasu — जब वसंत आता है, तो चेरी के फूल खिलते हैं) <button class=\"speak-btn\" data-speak=\"はるになると、さくらがさきます\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>निश्चित रूप से होने वाली चीज़ों के लिए दोनों का अर्थ \"जब\" हो सकता है: みぎにまがると、ぎんこうがあります (migi ni magaru to, ginkou ga arimasu — अगर/जब आप दाएं मुड़ते हैं, तो वहां एक बैंक है) <button class=\"speak-btn\" data-speak=\"みぎにまがると、ぎんこうがあります\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">Quest Arena</a> में दोनों प्रकार के सशर्त वाक्यों को आज़माएं, फिर <a href=\"#\" data-goto-tab=\"builder\">Sentence Builder</a> में अपने खुद के अगर/जब वाक्य बनाएं।</p>\n                                </div>\n                            </div>","day-pane-15":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-diagram-project\" style=\"color: var(--accent-pink);\"></i> N3·2: सशर्त वाक्य II (Conditionals II) — ～ば और ～なら\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>दो और सशर्त रूप N3 के सेट को पूरा करते हैं। <strong>～ば</strong> काल्पनिक (hypothetical) शर्तों, कहावतों, और नकारात्मक \"अनिवार्यताओं\" के लिए उपयुक्त है। <strong>～なら</strong> दूसरे व्यक्ति द्वारा पहले ही कही गई किसी बात पर प्रतिक्रिया देता है — \"अगर ऐसी बात है तो...\"</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～ば बनाना</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>समूह</th><th>नियम</th><th>उदाहरण</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>う-verbs</td><td>-u → -e + ば</td><td>のむ → <span class=\"ja-word\">のめば</span> (nomu → nomeba — पीना → अगर [आप] पीते हैं)</td></tr>\n                                            <tr><td>る-verbs</td><td>る हटाएं + れば</td><td>たべる → <span class=\"ja-word\">たべれば</span> (taberu → tabereba — खाना → अगर [आप] खाते हैं)</td></tr>\n                                            <tr><td>अनियमित</td><td>—</td><td>する → <span class=\"ja-word\">すれば</span>, くる → <span class=\"ja-word\">くれば</span> (suru → sureba, kuru → kureba)</td></tr>\n                                            <tr><td>い-adjectives</td><td>い → ければ</td><td>たかい → <span class=\"ja-word\">たかければ</span> (takai → takakereba — अगर [यह] महंगा है)</td></tr>\n                                            <tr><td>कोई भी नकारात्मक रूप</td><td>～ない → なければ</td><td>たべない → <span class=\"ja-word\">たべなければ</span> (tabenai → tabenakereba — अगर [आप] नहीं खाते)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top:8px;font-size:0.85rem;color:var(--text-muted);\">यह नकारात्मक ば-रूप बिल्कुल वही है जिस पर ～なければならない (\"अवश्य करना चाहिए\") आधारित है।</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～なら — किसी पूर्वधारणा (premise) पर प्रतिक्रिया</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>संज्ञाएं (nouns) और な-adjectives सीधे जुड़ते हैं, बिना だ के: <span class=\"ja-word\">げんきなら</span> (genki nara — अगर [आप] ऊर्जावान हैं), कभी भी げんきだなら नहीं।</li>\n                                        <li>なら उस विषय का जवाब देता है जिसे दूसरे व्यक्ति ने अभी उठाया है: A: にほんへいきます。 B: にほんへいくなら、パスポートがひつようです。 (nihon e iku nara, pasupooto ga hitsuyou desu — अगर आप जापान जा रहे हैं, तो आपको पासपोर्ट की ज़रूरत होगी) <button class=\"speak-btn\" data-speak=\"にほんへいくなら、パスポートがひつようです。\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>～たら/～と/～ば के विपरीत, परिणाम समय में तार्किक रूप से なら-उपवाक्य से पहले भी आ सकता है — यह पूर्वधारणा पर टिप्पणी कर रहा है, किसी सख्त क्रम का वर्णन नहीं।</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～ば～ほど — \"जितना..., उतना...\"</div>\n                                    <p>क्रिया को दोहराएं: ～ば रूप + सामान्य रूप (plain form) + ほど।</p>\n                                    <ul class=\"bullet-list\">\n                                        <li>たべればたべるほど、ふとります (tabereba taberu hodo, futorimasu — जितना ज़्यादा आप खाते हैं, उतना ज़्यादा आपका वज़न बढ़ता है) <button class=\"speak-btn\" data-speak=\"たべればたべるほど、ふとります\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">Quest Arena</a> में ば और なら का अभ्यास करें, फिर <a href=\"#\" data-goto-tab=\"bridge\">Grammar Bridge</a> पर अपने व्याकरण नोट्स जांचें।</p>\n                                </div>\n                            </div>","day-pane-16":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-cloud-rain\" style=\"color: var(--accent-pink);\"></i> N3·3: कर्मवाच्य (Passive) — ～られる\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>कर्मवाच्य (passive voice) किसी क्रिया का वर्णन करता है जो विषय (subject) <em>पर</em> की जाती है — और जापानी भाषा इसे अंग्रेज़ी से भी आगे ले जाती है, जिससे वक्ता किसी और के कार्य से पूरी तरह नकारात्मक रूप से प्रभावित होने का वर्णन कर सकता है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. कर्मवाच्य (passive) बनाना</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>समूह</th><th>नियम</th><th>उदाहरण</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>う-verbs</td><td>-u → -a + れる (う → わ)</td><td>のむ → <span class=\"ja-word\">のまれる</span> (nomu → nomareru); かう → <span class=\"ja-word\">かわれる</span> (kau → kawareru)</td></tr>\n                                            <tr><td>う-verbs जो う में समाप्त होते हैं</td><td>う → われる</td><td>かう → <span class=\"ja-word\">かわれる</span> (kau → kawareru — खरीदना → खरीदा जाना)</td></tr>\n                                            <tr><td>る-verbs</td><td>る हटाएं + られる</td><td>たべる → <span class=\"ja-word\">たべられる</span> (taberu → taberareru — खाना → खाया जाना)</td></tr>\n                                            <tr><td>अनियमित</td><td>—</td><td>する → <span class=\"ja-word\">される</span>, くる → <span class=\"ja-word\">こられる</span> (suru → sareru, kuru → korareru)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top:8px;font-size:0.85rem;color:var(--text-muted);\">ध्यान दें: る-verb का कर्मवाच्य (passive) और सामर्थ्यवाच्य (potential) (N4·6) रूप एक जैसा ही होता है — प्रसंग (context) से ही इनमें अंतर पता चलता है।</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. प्रत्यक्ष कर्मवाच्य (direct passive) — कर्ता (agent) को चिह्नित करना</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>\"के द्वारा\" वाले कर्ता (agent) को に से चिह्नित किया जाता है, या रचनात्मक/अवैयक्तिक (creative/impersonal) कार्यों के लिए によって से।</li>\n                                        <li>わたしはせんせいにほめられた (watashi wa sensei ni homerareta — मेरी अध्यापक द्वारा प्रशंसा की गई) <button class=\"speak-btn\" data-speak=\"わたしはせんせいにほめられた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>このほんはなつめそうせきによってかかれた (kono hon wa Natsume Souseki ni yotte kakareta — यह किताब नात्सुमे सोसेकी द्वारा लिखी गई थी) <button class=\"speak-btn\" data-speak=\"このほんはなつめそうせきによってかかれた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. कष्ट कर्मवाच्य (迷惑の受身)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>यह विशुद्ध रूप से जापानी विशेषता है: बिना प्रत्यक्ष कर्म (direct object) वाली क्रियाएं भी कर्मवाच्य ले सकती हैं, यह दिखाने के लिए कि वक्ता किसी और के कार्य से असुविधा में पड़ा।</li>\n                                        <li>あめにふられた (ame ni furareta — मैं बारिश में भीग गया [और यह परेशानी भरा था]) <button class=\"speak-btn\" data-speak=\"あめにふられた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>ともだちにこられて、べんきょうできなかった (tomodachi ni korarete, benkyou dekinakatta — एक दोस्त [मुझ पर] आ गया और मैं पढ़ाई नहीं कर सका)</li>\n                                        <li>अंग्रेज़ी अनुवाद शायद ही कभी इस बारीकी (nuance) को पकड़ पाता है — इसे \"मैं X के होने से परेशान हुआ\" के रूप में सोचें, शाब्दिक अनुवाद के रूप में नहीं।</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">Quest Arena</a> में कर्मवाच्य के कर्ता (agent) को पहचानें, फिर <a href=\"#\" data-goto-tab=\"builder\">Sentence Builder</a> में खुद कुछ कष्ट-कर्मवाच्य वाक्य बनाएं।</p>\n                                </div>\n                            </div>","day-pane-17":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-people-arrows\" style=\"color: var(--accent-pink);\"></i> N3·4: प्रेरणार्थक (Causative) और प्रेरणार्थक-कर्मवाच्य (Causative-Passive)\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>प्रेरणार्थक (causative) यह बताता है कि किसी से कुछ करवाना या करने देना। इसे कर्मवाच्य (passive) के साथ जोड़ने पर प्रेरणार्थक-कर्मवाच्य (causative-passive) बनता है: किसी ऐसी चीज़ के लिए मजबूर किया जाना जो आप नहीं करना चाहते थे।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. प्रेरणार्थक (causative) बनाना (～せる／させる)</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>समूह</th><th>नियम</th><th>उदाहरण</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>う-verbs</td><td>-u → -a + せる (う → わ)</td><td>のむ → <span class=\"ja-word\">のませる</span> (nomu → nomaseru); かう → <span class=\"ja-word\">かわせる</span> (kau → kawaseru)</td></tr>\n                                            <tr><td>る-verbs</td><td>る हटाएं + させる</td><td>たべる → <span class=\"ja-word\">たべさせる</span> (taberu → tabesaseru — खाना → [किसी को] खाने के लिए मजबूर करना/खाने देना)</td></tr>\n                                            <tr><td>अनियमित</td><td>—</td><td>する → <span class=\"ja-word\">させる</span>, くる → <span class=\"ja-word\">こさせる</span> (suru → saseru, kuru → kosaseru)</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. \"करवाना\" बनाम \"करने देना\" — और किसे に या を मिलता है</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>はははこどもにやさいをたべさせた (haha wa kodomo ni yasai o tabesaseta — मां ने बच्चे को सब्ज़ियां खिलाईं/खाने पर मजबूर किया) <button class=\"speak-btn\" data-speak=\"はははこどもにやさいをたべさせた\"><i class=\"fa-solid fa-volume-high\"></i></button> — सकर्मक क्रिया (transitive verb): मजबूर किए गए व्यक्ति को に लगता है।</li>\n                                        <li>せんせいはがくせいをはやくかえらせた (sensei wa gakusei o hayaku kaeraseta — अध्यापक ने छात्रों को जल्दी घर भेज दिया/मजबूर किया) — अकर्मक क्रिया (intransitive verb) かえる: मजबूर किए गए व्यक्ति को を लगता है।</li>\n                                        <li>प्रसंग (context) और लहजा (tone) तय करते हैं कि यह \"करवाना\" (ज़बरदस्ती वाला) है या \"करने देना\" (अनुमति वाला): どうぞやすませてください (douzo yasumasete kudasai — कृपया मुझे आराम करने दें) स्पष्ट रूप से अनुमति वाला है।</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. प्रेरणार्थक-कर्मवाच्य (～させられる) — किसी काम के लिए मजबूर किया जाना</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>इसे प्रेरणार्थक स्टेम (causative stem) + られる से बनाएं: たべさせる → <span class=\"ja-word\">たべさせられる</span> (tabesaseru → tabesaserareru — खाने के लिए मजबूर किया गया)।</li>\n                                        <li>う-verbs अक्सर ～せられる को छोटा करके ～される बना देते हैं: のませられる → <span class=\"ja-word\">のまされる</span> (nomaserareru → nomasareru) — दोनों रूप सही हैं; छोटा किया हुआ रूप बोलचाल में ज़्यादा आम है।</li>\n                                        <li>わたしはははにやさいをたべさせられた (watashi wa haha ni yasai o tabesaserareta — मुझे मेरी मां ने सब्ज़ियां खाने के लिए मजबूर किया [और मैं नहीं करना चाहता था]) <button class=\"speak-btn\" data-speak=\"わたしはははにやさいをたべさせられた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">Quest Arena</a> में प्रेरणार्थक बनाम प्रेरणार्थक-कर्मवाच्य वाक्यों को सुलझाएं, फिर <a href=\"#\" data-goto-tab=\"flashcards\">Flashcards</a> से इन रूपों का अभ्यास करें।</p>\n                                </div>\n                            </div>","day-pane-18":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-gavel\" style=\"color: var(--accent-pink);\"></i> N3·5: परिवर्तन और निर्णय\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>ये चार पैटर्न देखने में एक जैसे लगते हैं लेकिन दो पंक्तियों में बंटे हैं: <strong>なる</strong> (बनना) एक ऐसे परिवर्तन का वर्णन करता है जो अपने आप होता है, जबकि <strong>する</strong> (करना) एक जानबूझकर किए गए कार्य का वर्णन करता है — और <strong>よう</strong> (एक स्थिति/क्षमता) की तुलना <strong>こと</strong> (एक तथ्य/निर्णय) से होती है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～ようになる — स्थिति या क्षमता में बदलाव</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>सामर्थ्यवाच्य (potential)/dictionary रूप + ようになる — समय के साथ आने वाला एक धीरे-धीरे, प्राकृतिक बदलाव।</li>\n                                        <li>かんじがよめるようになった (kanji ga yomeru you ni natta — मैं कांजी पढ़ पाने लगा हूं [पहले नहीं पढ़ पाता था]) <button class=\"speak-btn\" data-speak=\"かんじがよめるようになった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>まいにちにほんごをはなすようになりました (mainichi nihongo o hanasu you ni narimashita — मैं अब हर दिन जापानी बोलने लगा हूं)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～ことになる — दूसरों द्वारा तय किया गया, या एक व्यवस्था</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>dictionary/ない-रूप + ことになる — यह किसी परिस्थिति, समूह, या किसी अन्य व्यक्ति द्वारा लिए गए निर्णय की घोषणा करता है — वक्ता व्यक्तिगत रूप से नहीं।</li>\n                                        <li>らいげつ、とうきょうにてんきんすることになった (raigetsu, Tokyo ni tenkin suru koto ni natta — यह तय हो गया है कि मैं अगले महीने टोक्यो ट्रांसफर हो जाऊंगा) <button class=\"speak-btn\" data-speak=\"らいげつ、とうきょうにてんきんすることになった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～ようにする／～ことにする — जानबूझकर किए जाने वाले रूप</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>～ようにする:</strong> dictionary/ない-रूप + ようにする — एक निरंतर, सचेत प्रयास या आदत। まいにちうんどうするようにしています (mainichi undou suru you ni shiteimasu — मैं हर दिन व्यायाम करने का विशेष ध्यान रखता हूं)</li>\n                                        <li><strong>～ことにする:</strong> dictionary/ない-रूप + ことにする — वक्ता की अपनी इच्छा से लिया गया एक बार का व्यक्तिगत निर्णय। かいしゃをやめることにした (kaisha o yameru koto ni shita — मैंने कंपनी छोड़ने का फैसला किया है) <button class=\"speak-btn\" data-speak=\"かいしゃをやめることにした\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">Quest Arena</a> में なる बनाम する को सुलझाएं, फिर <a href=\"#\" data-goto-tab=\"bridge\">Grammar Bridge</a> पर अपनी समझ जांचें।</p>\n                                </div>\n                            </div>","day-pane-19":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-ear-listen\" style=\"color: var(--accent-pink);\"></i> N3·6: सुनी-सुनाई बात (Hearsay) और प्रतीति (Appearance)\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>\"ऐसा लगता है\" या \"मैंने सुना है कि\" कहने के चार तरीके — और इनमें से एक, そうだ, इस पर निर्भर करते हुए कि यह कैसे जुड़ता है, दो बिल्कुल अलग-अलग अर्थ रखता है। जुड़ने का नियम सही से समझ लें तो बाकी सब अपने आप स्पष्ट हो जाता है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. そうだ — सुनी-सुनाई बात बनाम प्रतीति (यहीं चूक होती है)</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>अर्थ</th><th>किससे जुड़ता है</th><th>उदाहरण</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>सुनी-सुनाई बात (伝聞) — \"मैंने सुना है कि...\"</td><td>सामान्य रूप, कोई भी काल (noun/な-adj + だ)</td><td>あしたはあめだそうです (ashita wa ame da sou desu — मैंने सुना है कि कल बारिश होगी) <button class=\"speak-btn\" data-speak=\"あしたはあめだそうです\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>प्रतीति (様態) — \"ऐसा दिखता/लगता है...\"</td><td>क्रिया का ます-स्टेम / विशेषण का स्टेम (बिना い, बिना だ)</td><td>あめがふりそうです (ame ga furisou desu — ऐसा लगता है कि बारिश होने वाली है) <button class=\"speak-btn\" data-speak=\"あめがふりそうです\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                        </tbody>\n                                    </table>\n                                    <ul class=\"bullet-list\">\n                                        <li>सुनी-सुनाई बात वाला そうだ संज्ञाओं/な-adjectives से पहले だ को कभी नहीं छोड़ता: これはぺんだそうです (kore wa pen da sou desu — मैंने सुना है कि यह एक पेन है)।</li>\n                                        <li>प्रतीति वाला そうだ だ को पूरी तरह छोड़ देता है और सीधे स्टेम से जुड़ता है: おいしい → <span class=\"ja-word\">おいしそう</span> (oishii → oishisou — स्वादिष्ट लगता है); げんき → <span class=\"ja-word\">げんきそう</span> (genki → genkisou — ठीक/स्वस्थ लगता है)।</li>\n                                        <li>दो अनियमित प्रतीति-स्टेम: いい → <span class=\"ja-word\">よさそう</span> (ii → yosasou, न कि iisou); ない → <span class=\"ja-word\">なさそう</span> (nai → nasasou)।</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. らしい — दूरी वाली सुनी-सुनाई बात, या \"की खासियत\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>सामान्य रूप (plain form) (संज्ञा बिना だ के) + らしい — सुनी हुई किसी बात को बताता है, आमतौर पर そうだ की तुलना में ज़्यादा दूरी/अनिश्चितता के साथ, अक्सर किसी सीधे स्रोत की बजाय आम अफवाह से।</li>\n                                        <li>たなかさんはらいげつけっこんするらしいです (Tanaka-san wa raigetsu kekkon suru rashii desu — मैंने सुना है कि तनाका अगले महीने शादी कर रहे हैं) <button class=\"speak-btn\" data-speak=\"たなかさんはらいげつけっこんするらしいです\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>इसका अर्थ \"की खासियत / जैसा\" भी होता है: おとこらしい (otoko rashii — मर्दाना, एक \"असली मर्द\" जैसा)।</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. みたい और ようだ — जो देखा उससे अनुमान</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>दोनों का अर्थ है \"लगता है/जैसा दिखता है,\" जो अवलोकन (observation) या तुलना पर आधारित है — みたい अनौपचारिक (casual) है, ようだ ज़्यादा औपचारिक/लिखित (formal/written) रूप है।</li>\n                                        <li>संज्ञाएं/な-adjectives: みたい सीधे जुड़ता है (あめみたい); ようだ को の／な की ज़रूरत होती है (あめのようだ, げんきなようだ)।</li>\n                                        <li>あのひとはがくせいみたいです (ano hito wa gakusei mitai desu — वह व्यक्ति एक छात्र जैसा लगता है)</li>\n                                        <li>かれはびょうきのようだ (kare wa byouki no you da — वह बीमार लगता है)</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">Quest Arena</a> में सुनी-सुनाई बात और प्रतीति में फर्क पहचानें, फिर <a href=\"#\" data-goto-tab=\"flashcards\">Flashcards</a> से चारों पर खुद को परखें।</p>\n                                </div>\n                            </div>","day-pane-20":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-toolbox\" style=\"color: var(--accent-pink);\"></i> N3·7: Te-रूप के विस्तार (Te-form Extensions)\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>Te-रूप N3 में भी अपनी उपयोगिता साबित करता रहता है — इसमें おく, しまう, ある, या みる जोड़ने से चार और रोज़मर्रा की बारीकियां खुल जाती हैं।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～ておく — पहले से कर लेना, या जैसा है वैसा छोड़ देना</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>किसी चीज़ को पहले से तैयार करता है, या भविष्य के फायदे के लिए किसी चीज़ को जैसी है वैसी छोड़ देता है।</li>\n                                        <li>ビールをかっておく (biiru o katte oku — बीयर पहले से खरीद कर रखना [बाद की पार्टी के लिए]) <button class=\"speak-btn\" data-speak=\"ビールをかっておく\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>बोलचाल की भाषा ～ておく को छोटा करके ～とく बना देती है: かっておく → <span class=\"ja-word\">かっとく</span> (katte oku → kattoku)।</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～てしまう — पूर्णता, या \"ओह-नहीं\" वाला भाव</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>इस बात पर ज़ोर देता है कि कुछ पूरी तरह से समाप्त हो गया है, अक्सर पछतावे या अनजाने में किए गए कार्य की भावना के साथ।</li>\n                                        <li>しゅくだいをやってしまった (shukudai o yatte shimatta — मैंने होमवर्क पूरा कर ही दिया) <button class=\"speak-btn\" data-speak=\"しゅくだいをやってしまった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>बोलचाल में संक्षिप्त रूप: ～てしまう → ～ちゃう (या ～でしまう → ～じゃう): たべてしまう → <span class=\"ja-word\">たべちゃう</span> (tabete shimau → tabechau)।</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～てある बनाम ～ている, और ～てみる — \"करके देखना\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>～てある</strong> (सकर्मक क्रिया (transitive verb) + ある): किसी के द्वारा जानबूझकर छोड़ी गई एक स्थिति। まどがあけてある (mado ga akete aru — खिड़की [जानबूझकर] खुली छोड़ी गई है) <button class=\"speak-btn\" data-speak=\"まどがあけてある\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong>～ている</strong> से तुलना करें: まどがあいている (mado ga aiteiru — खिड़की खुली है) — एक सामान्य स्थिति, इस पर कोई ज़ोर नहीं कि इसे किसने और क्यों ऐसा छोड़ा।</li>\n                                        <li><strong>～てみる:</strong> यह देखने के लिए कि क्या होता है, कुछ \"करके देखना\"। たべてみる (tabete miru — [इसे] खाकर देखना)</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">Quest Arena</a> में सही te-रूप विस्तार चुनें, फिर <a href=\"#\" data-goto-tab=\"builder\">Sentence Builder</a> के साथ इन्हें अपने खुद के वाक्यों में इस्तेमाल करें।</p>\n                                </div>\n                            </div>","day-pane-21":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-crown\" style=\"color: var(--accent-pink);\"></i> N3·8: केइगो (Keigo) I — सम्मानसूचक और विनयसूचक क्रियाएं\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p><strong>敬語 (keigo)</strong> जापान की सम्मानजनक भाषा (respectful speech) की व्यवस्था है। <strong>尊敬語</strong> (सम्मानसूचक/honorific) किसी और के कार्य को ऊंचा उठाता है; <strong>謙譲語</strong> (विनयसूचक/humble) सुनने वाले के प्रति सम्मान दिखाने के लिए आपके अपने कार्य को नीचा दिखाता है। कुछ सबसे आम क्रियाओं के केइगो रूप पूरी तरह अनियमित होते हैं — इन्हें सबसे पहले सीखें।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. सामान्य → सम्मानसूचक → विनयसूचक</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>सामान्य</th><th>सम्मानसूचक (尊敬語)</th><th>विनयसूचक (謙譲語)</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>いる (iru — होना)</td><td><span class=\"ja-word\">いらっしゃる</span> (irassharu)</td><td><span class=\"ja-word\">おる</span> (oru)</td></tr>\n                                            <tr><td>いく／くる (iku/kuru — जाना/आना)</td><td><span class=\"ja-word\">いらっしゃる</span> (irassharu)</td><td><span class=\"ja-word\">まいる</span> (mairu)</td></tr>\n                                            <tr><td>いう (iu — कहना)</td><td><span class=\"ja-word\">おっしゃる</span> (ossharu)</td><td><span class=\"ja-word\">もうす</span> (mousu)</td></tr>\n                                            <tr><td>たべる／のむ (taberu/nomu — खाना/पीना)</td><td><span class=\"ja-word\">めしあがる</span> (meshiagaru)</td><td><span class=\"ja-word\">いただく</span> (itadaku)</td></tr>\n                                            <tr><td>する (suru — करना)</td><td><span class=\"ja-word\">なさる</span> (nasaru)</td><td><span class=\"ja-word\">いたす</span> (itasu)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"font-size:0.85rem;color:var(--text-muted);\">सम्मानसूचक क्रियाएं <strong>दूसरे लोगों के</strong> कार्यों को ऊंचा उठाती हैं (एक अध्यापक, एक ग्राहक, आपका बॉस); विनयसूचक क्रियाएं सुनने वाले के प्रति सम्मान दिखाने के लिए <strong>आपके अपने</strong> कार्यों को नीचा दिखाती हैं। एक ही व्यक्ति के लिए इन दोनों को कभी न मिलाएं।</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ます-रूप पर ध्यान दें — चार अनियमित रूप</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>いらっしゃる, おっしゃる, なさる, और くださる — ये सभी ～ります नहीं बल्कि ～います लेते हैं: いらっしゃる → <span class=\"ja-word\">いらっしゃいます</span> (irassharu → irasshaimasu), おっしゃる → <span class=\"ja-word\">おっしゃいます</span> (ossharu → osshaimasu)।</li>\n                                        <li>せんせいはいついらっしゃいますか (sensei wa itsu irasshaimasu ka — अध्यापक कब आएंगे?) <button class=\"speak-btn\" data-speak=\"せんせいはいついらっしゃいますか\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>しゃちょうはなんとおっしゃいましたか (shachou wa nan to osshaimashita ka — अध्यक्ष (president) ने क्या कहा?) <button class=\"speak-btn\" data-speak=\"しゃちょうはなんとおっしゃいましたか\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. विनयसूचक व्यवहार में — खुद को नीचा दिखाना</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>たなかともうします (Tanaka to moushimasu — मुझे तनाका कहा जाता है [विनयसूचक आत्म-परिचय]) <button class=\"speak-btn\" data-speak=\"たなかともうします\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>わたしはあしたまいります (watashi wa ashita mairimasu — मैं कल जाऊंगा/आऊंगा [विनयसूचक])</li>\n                                        <li>どうぞめしあがってください (douzo meshiagatte kudasai — कृपया खाइए [सम्मानसूचक, किसी अतिथि से कहा गया])</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">Quest Arena</a> में सम्मानसूचक और विनयसूचक जोड़ों का मिलान करें, फिर <a href=\"#\" data-goto-tab=\"flashcards\">Flashcards</a> के साथ पूरी केइगो तालिका की समीक्षा करें।</p>\n                                </div>\n                            </div>","day-pane-22":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-scroll\" style=\"color: var(--accent-pink);\"></i> N2·1: ～ものだ समूह\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>もの (\"चीज़़\") यहाँ तीन बिल्कुल अलग रूपों में ढलता है: <strong>ものだ</strong> किसी आम सच्चाई, पुरानी याद या हल्की नसीहत को बताता है; <strong>ものの</strong> पहले किसी बात को मान लेता है और फिर किसी विपरीत बात की ओर मुड़ जाता है; <strong>ものだから</strong> अभी हुई किसी बात की सफ़ाई देने के लिए एक कारण का सहारा लेता है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ものだ — तीन भाव, एक ही अंत</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>प्रयोग</th><th>नियम</th><th>उदाहरण</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>आम सच्चाई</td><td>सामान्य रूप + ものだ</td><td>ひとはだれでもしっぱいするものだ (hito wa dare demo shippai suru mono da — हर कोई गलती करता है, बस ऐसा ही होता है) <button class=\"speak-btn\" data-speak=\"ひとはだれでもしっぱいするものだ\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>पुरानी याद (बीती आदत)</td><td>た-form + ものだ</td><td>こどものころ、よくこのかわでおよいだものだ (kodomo no koro, yoku kono kawa de oyoida mono da — बचपन में, मैं अक्सर इस नदी में तैरा करता था) <button class=\"speak-btn\" data-speak=\"こどものころ、よくこのかわでおよいだものだ\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>हल्की नसीहत (\"चाहिए\")</td><td>सामान्य रूप + ものだ</td><td>あいさつはきちんとするものだ (aisatsu wa kichinto suru mono da — अभिवादन सही तरीके से करना चाहिए)</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ものの — हालांकि, लेकिन फिर भी...</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>सामान्य रूप (किसी भी काल में) + ものの पहले एक तथ्य स्वीकार करता है, फिर कोई अप्रत्याशित या निराशाजनक नतीजा बताता है — यह けれども से ज़्यादा औपचारिक/लिखित शैली का माना जाता है।</li>\n                                        <li>にほんごをさんねんべんきょうしたものの、まだうまくはなせない (nihongo o sannen benkyou shita mono no, mada umaku hanasenai — मैंने तीन साल जापानी की पढ़ाई की, फिर भी अभी तक अच्छी तरह बोल नहीं पाता) <button class=\"speak-btn\" data-speak=\"にほんごをさんねんべんきょうしたものの、まだうまくはなせない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>あたまではわかっているものの、なかなかじっこうできない (atama de wa wakatteiru mono no, nakanaka jikkou dekinai — मैं इसे दिमाग़ से समझता हूँ, फिर भी इसे आसानी से अमल में नहीं ला पाता)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ものだから — बहाने वाला कारण</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>सामान्य रूप + ものだから एक ऐसा कारण देता है जो साथ ही बहाना भी बन जाता है, आमतौर पर इसके बाद माफ़ी या स्पष्टीकरण आता है — यह बोलचाल की जापानी में आम है।</li>\n                                        <li>でんしゃがおくれたものだから、ちこくしてしまいました (densha ga okureta mono da kara, chikoku shite shimaimashita — ट्रेन लेट हो गई थी, इसीलिए मुझे देर हो गई) <button class=\"speak-btn\" data-speak=\"でんしゃがおくれたものだから、ちこくしてしまいました\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>बोलचाल में यह छोटा हो जाता है: ものだから → もんだから (mono da kara → mon da kara)।</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>もの के तीनों अंत <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट एरिना</a> में पहचानें, फिर <a href=\"#\" data-goto-tab=\"flashcards\">फ़्लैशकार्ड्स</a> से उनका अभ्यास करें।</p>\n                                </div>\n                            </div>","day-pane-23":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-scale-balanced\" style=\"color: var(--accent-pink);\"></i> N2·2: ～わけだ समूह\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>わけ (\"कारण/परिस्थिति\") से N2 के तीन अहम पैटर्न बनते हैं। <strong>わけだ</strong> स्वाभाविक निष्कर्ष निकालता है — \"तो इसीलिए, मतलब यह है कि...\"; <strong>わけではない</strong> किसी सामान्य बयान को नरम करके \"ज़रूरी नहीं कि...\" का भाव देता है; और <strong>わけにはいかない</strong> बताता है कि कोई सामाजिक या नैतिक ज़िम्मेदारी किसी काम को होने से रोक देती है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. わけだ — तो इसीलिए / मतलब यह है कि</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>सामान्य रूप + わけだ अभी कही या देखी गई बात से तार्किक रूप से निकलने वाला निष्कर्ष बताता है।</li>\n                                        <li>さんねんかんにほんにすんでいた。だから、にほんごがじょうずなわけだ (san-nen kan nihon ni sundeita. dakara, nihongo ga jouzu na wake da — वे तीन साल जापान में रहे थे। तो इसीलिए उनकी जापानी अच्छी है) <button class=\"speak-btn\" data-speak=\"さんねんかんにほんにすんでいた。だから、にほんごがじょうずなわけだ\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>どうりでさむいわけだ、ゆきがふっている (douri de samui wake da, yuki ga futteiru — तो इसीलिए ठंड है, बर्फ़ गिर रही है) <button class=\"speak-btn\" data-speak=\"どうりでさむいわけだ、ゆきがふっている\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. わけではない — ऐसा नहीं है कि... / ज़रूरी नहीं</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>सामान्य रूप + わけではない किसी धारणा को पूरी तरह ख़ारिज किए बिना आंशिक रूप से नकारता है।</li>\n                                        <li>きらいなわけではないが、あまりたべたくない (kirai na wake de wa nai ga, amari tabetakunai — ऐसा नहीं है कि मुझे यह नापसंद है, पर मेरा इसे खाने का मन ज़्यादा नहीं है) <button class=\"speak-btn\" data-speak=\"きらいなわけではないが、あまりたべたくない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>ぜんぶわかったわけではない (zenbu wakatta wake de wa nai — ऐसा नहीं है कि मुझे सब कुछ समझ आ गया)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. わけにはいかない — ऐसा करने की गुंजाइश नहीं / यूँ ही नहीं कर सकते</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>डिक्शनरी रूप + わけにはいかない: कोई सामाजिक, नैतिक या परिस्थितिजन्य ज़िम्मेदारी किसी काम को रोक देती है, भले ही आप वह करना चाहें।</li>\n                                        <li>あしたはしけんがあるから、きょうはあそぶわけにはいかない (ashita wa shiken ga aru kara, kyou wa asobu wake ni wa ikanai — कल मेरी परीक्षा है, इसलिए आज मैं यूँ ही खेलने नहीं जा सकता) <button class=\"speak-btn\" data-speak=\"あしたはしけんがあるから、きょうはあそぶわけにはいかない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>इसका नकारात्मक रूप, ないわけにはいかない (\"न करने की गुंजाइश नहीं\"), अगले पाठ में अलग से पढ़ेंगे।</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट एरिना</a> में わけだ और わけではない के बीच फ़र्क समझें, फिर <a href=\"#\" data-goto-tab=\"bridge\">ग्रामर ब्रिज</a> पर अपने नोट्स जांच लें।</p>\n                                </div>\n                            </div>","day-pane-24":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-hand-fist\" style=\"color: var(--accent-pink);\"></i> N2·3: बाध्यता और मजबूरी\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>\"मेरे पास कोई चारा नहीं\" कहने के तीन भारी-भरकम तरीके। <strong>～ざるを得ない</strong> ऐसी मजबूरी है जो हालात के आगे बेमन से माननी पड़े। <strong>～ずにはいられない</strong> इतनी तेज़ भावनात्मक इच्छा है जिसे रोका न जा सके। <strong>～ないわけにはいかない</strong> एक सामाजिक या नैतिक कर्तव्य है जिसे टाला नहीं जा सकता।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～ざるを得ない (और ～ずにはいられない) कैसे बनाएं</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>समूह</th><th>नियम</th><th>उदाहरण</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>う-verbs</td><td>ない-form stem + ざるを得ない</td><td>のむ → のまない → <span class=\"ja-word\">のまざるをえない</span> (nomu → nomanai → nomazaru o enai — पीना → पीने के अलावा कोई चारा नहीं)</td></tr>\n                                            <tr><td>る-verbs</td><td>ない-form stem + ざるを得ない</td><td>やめる → やめない → <span class=\"ja-word\">やめざるをえない</span> (yameru → yamenai → yamezaru o enai — छोड़ना → छोड़ने के अलावा कोई चारा नहीं)</td></tr>\n                                            <tr><td>अनियमित する</td><td>せざるを得ない, न कि さざるを得ない</td><td>する → <span class=\"ja-word\">せざるをえない</span> (suru → sezaru o enai)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top:8px;font-size:0.85rem;color:var(--text-muted);\">～ずにはいられない भी उसी तरह बनता है — बस ざるを得ない की जगह ずにはいられない लगा दें (अनियमित する → せずにはいられない, वही せ जो ऊपर है)।</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～ざるを得ない व्यवहार में — बेमन की मजबूरी</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>きゅうりょうがやすいので、やめざるをえない (kyuuryou ga yasui node, yamezaru o enai — तनख़्वाह कम है, इसलिए छोड़ने के अलावा कोई चारा नहीं) <button class=\"speak-btn\" data-speak=\"きゅうりょうがやすいので、やめざるをえない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>じょうしにいわれたら、ざんぎょうせざるをえない (joushi ni iwaretara, zangyou sezaru o enai — अगर बॉस कहे, तो ओवरटाइम करने के अलावा कोई चारा नहीं) <button class=\"speak-btn\" data-speak=\"じょうしにいわれたら、ざんぎょうせざるをえない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～ずにはいられない बनाम ～ないわけにはいかない</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>～ずにはいられない एक ऐसा भावनात्मक आवेग है जिसे रोकना मुश्किल है: あのえいがをみると、なかずにはいられない (ano eiga o miru to, nakazu ni wa irarenai — जब मैं वह फ़िल्म देखता हूँ, तो रोए बिना नहीं रह पाता) <button class=\"speak-btn\" data-speak=\"あのえいがをみると、なかずにはいられない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>～ないわけにはいかない (ない-form + わけにはいかない) एक सामाजिक या नैतिक कर्तव्य है जिसे टाला नहीं जा सकता: せんせいによばれたら、いかないわけにはいかない (sensei ni yobaretara, ikanai wake ni wa ikanai — अगर शिक्षक बुलाएं, तो न जाना नहीं हो सकता) <button class=\"speak-btn\" data-speak=\"せんせいによばれたら、いかないわけにはいかない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>फ़र्क: ざるを得ない का इशारा है \"कोई व्यावहारिक विकल्प नहीं\"; ないわけにはいかない का इशारा है \"कर्तव्य कहता है कि करना ही होगा।\"</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>तीनों \"कोई चारा नहीं\" वाले पैटर्न का <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट एरिना</a> में अभ्यास करें, फिर <a href=\"#\" data-goto-tab=\"builder\">सेंटेंस बिल्डर</a> से अपने ख़ुद के वाक्य बनाएं।</p>\n                                </div>\n                            </div>","day-pane-25":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-scale-unbalanced\" style=\"color: var(--accent-pink);\"></i> N2·4: रियायती वाक्य (Concessives)\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>उम्मीद और असलियत के बीच के फ़र्क को दिखाने के तीन तरीके। <strong>にもかかわらず</strong> सबसे मज़बूत रूप है — \"इसके बावजूद/हालांकि\"। <strong>にしては</strong> किसी चीज़ को उसकी श्रेणी से बनने वाली उम्मीद के मुक़ाबले आंकता है। <strong>わりに(は)</strong> बताता है कि नतीजा दी गई शर्त के अनुपात में नहीं है — यह にしては का ही हल्का और ज़्यादा तटस्थ रूप है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. にもかかわらず — इसके बावजूद / के बावजूद</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>सामान्य रूप / संज्ञा + にもかかわらず पहले एक तथ्य बताता है, फिर कोई हैरान करने वाला या विपरीत नतीजा — यह औपचारिक है और लेखन में आम है।</li>\n                                        <li>あめにもかかわらず、おおぜいのひとがきた (ame ni mo kakawarazu, oozei no hito ga kita — बारिश के बावजूद, बहुत सारे लोग आए) <button class=\"speak-btn\" data-speak=\"あめにもかかわらず、おおぜいのひとがきた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>いっしょうけんめいべんきょうしたにもかかわらず、しけんにおちてしまった (isshoukenmei benkyou shita ni mo kakawarazu, shiken ni ochite shimatta — जी-जान से पढ़ाई करने के बावजूद, मैं परीक्षा में फ़ेल हो गया) <button class=\"speak-btn\" data-speak=\"いっしょうけんめいべんきょうしたにもかかわらず、しけんにおちてしまった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. にしては — ...के लिए तो / देखते हुए (हैरानी वाला लहज़ा)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>संज्ञा / सामान्य रूप + にしては किसी व्यक्ति या चीज़ को उसकी श्रेणी से बनने वाले मापदंड के मुक़ाबले आंकता है: \"...के लिए तो, यह हैरानी की बात है।\"</li>\n                                        <li>こどもにしては、よくかんじをしっている (kodomo ni shite wa, yoku kanji o shitteiru — एक बच्चे के लिए तो, वह काफ़ी कांजी जानता है) <button class=\"speak-btn\" data-speak=\"こどもにしては、よくかんじをしっている\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>はじめてにしては、じょうずにできた (hajimete ni shite wa, jouzu ni dekita — पहली कोशिश के लिए तो, अच्छा हो गया)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. わりに(は) — अपेक्षाकृत / देखते हुए (तटस्थ लहज़ा)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>संज्ञा (+の) / な-adjective (+な) / सामान्य रूप + わりに(は): नतीजा उससे मेल नहीं खाता जो दी गई शर्त सामान्यतः दिखाती — にしては के विपरीत, यहाँ किसी तय \"मापदंड\" की ज़रूरत नहीं होती।</li>\n                                        <li>このみせはねだんがたかいわりには、あまりおいしくない (kono mise wa nedan ga takai wari ni wa, amari oishikunai — इस रेस्तराँ के महंगे होने को देखते हुए, यह ज़्यादा स्वादिष्ट नहीं है)</li>\n                                        <li>ねんれいのわりに、わかくみえる (nenrei no wari ni, wakaku mieru — वे अपनी उम्र के हिसाब से जवान दिखते हैं) <button class=\"speak-btn\" data-speak=\"ねんれいのわりに、わかくみえる\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट एरिना</a> में तीनों बेमेल पैटर्न को अलग-अलग पहचानें, फिर <a href=\"#\" data-goto-tab=\"bridge\">ग्रामर ब्रिज</a> पर बारीकियों के नोट्स दोहराएं।</p>\n                                </div>\n                            </div>","day-pane-26":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-wave-square\" style=\"color: var(--accent-pink);\"></i> N2·5: प्रवृत्तियाँ\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>किसी स्थिति की ओर \"झुकाव\" दिखाने के लिए तीन प्रत्यय, बिना पूरी तरह उस स्थिति में होने के। <strong>～がち</strong> बार-बार होने वाला पैटर्न है, जो आमतौर पर अवांछित होता है। <strong>～気味</strong> (ぎみ) एक हल्की, अक्सर शारीरिक, प्रवृत्ति है जो अभी हो रही है। <strong>～っぽい</strong> किसी चीज़ को \"-जैसा\" रंग देता है — किसी गुण या प्रकार से मिलता-जुलता।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～がち — की प्रवृत्ति होना / अक्सर ऐसा होना</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>ます-stem या संज्ञा + がち बार-बार होने वाली प्रवृत्ति दिखाता है, जो आमतौर पर किसी अवांछित बात की ओर होती है।</li>\n                                        <li>かれはやくそくをわすれがちだ (kare wa yakusoku o wasuregachi da — वह अक्सर अपने वादे भूल जाता है) <button class=\"speak-btn\" data-speak=\"かれはやくそくをわすれがちだ\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>このごろ、くもりがちのてんきがつづいている (kono goro, kumorigachi no tenki ga tsuzuiteiru — आजकल, मौसम अक्सर बादलों भरा रहा है)</li>\n                                        <li>एक आम रूढ़ प्रयोग: びょうきがち (byoukigachi — बीमार-सा, बार-बार बीमार पड़ने वाला)।</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～気味 (ぎみ) — थोड़ा-सा एहसास / थोड़ा</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>ます-stem या संज्ञा + 気味: अभी महसूस हो रही एक हल्की प्रवृत्ति या भाव, जो がち से ज़्यादा हल्का और शारीरिक/मानसिक होता है।</li>\n                                        <li>さいきん、つかれぎみだ (saikin, tsukaregimi da — आजकल मुझे थोड़ी थकान-सी महसूस हो रही है) <button class=\"speak-btn\" data-speak=\"さいきん、つかれぎみだ\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>かぜぎみなので、きょうははやくねます (kazegimi na node, kyou wa hayaku nemasu — मुझे थोड़ा ज़ुकाम-सा महसूस हो रहा है, इसलिए आज जल्दी सो जाऊँगा)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～っぽい — -सा/-जैसा / वैसा दिखना या करना</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>い-adjective stem / संज्ञा / ます-stem + っぽい किसी गुण का आभास देता है, जो अक्सर हल्का नकारात्मक या अनौपचारिक होता है।</li>\n                                        <li>わすれっぽいひとですね (wasureppoi hito desu ne — आप भुलक्कड़ इंसान हैं, है न) <button class=\"speak-btn\" data-speak=\"わすれっぽいひとですね\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>かのじょはこどもっぽい (kanojo wa kodomoppoi — वह बचकानी है)</li>\n                                        <li>みずっぽいスープ (mizuppoi suupu — पनीला सूप)</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"flashcards\">फ़्लैशकार्ड्स</a> से तीनों प्रवृत्तियों पर ख़ुद को परखें, फिर <a href=\"#\" data-goto-tab=\"builder\">सेंटेंस बिल्डर</a> से अपने वाक्यों में इनका इस्तेमाल करें।</p>\n                                </div>\n                            </div>","day-pane-27":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-arrow-trend-up\" style=\"color: var(--accent-pink);\"></i> N2·6: सहसंबंधित बदलाव\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>तीनों पैटर्न दो चीज़ों के साथ-साथ बदलने को दिखाते हैं — \"जैसे-जैसे X बदलता है, वैसे-वैसे Y भी बदलता है\" — और इनमें काफ़ी हद तक ओवरलैप है। लेकिन हर एक का झुकाव अलग है: <strong>につれて</strong> धीमा और स्वाभाविक बदलाव दिखाता है, <strong>に伴って</strong> इस बात पर ज़ोर देता है कि एक बदलाव दूसरे को जन्म देता है, और <strong>に従って</strong> किसी नियम के \"अनुसार\" चलने का मतलब भी रख सकता है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. तीनों को बनाना और उनकी तुलना करना</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>पैटर्न</th><th>बारीकी</th><th>उदाहरण</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>～につれて</td><td>धीमा, समानांतर स्वाभाविक बदलाव</td><td>としをとるにつれて、からだがよわくなる (toshi o toru ni tsurete, karada ga yowaku naru — जैसे-जैसे उम्र बढ़ती है, शरीर कमज़ोर होता जाता है) <button class=\"speak-btn\" data-speak=\"としをとるにつれて、からだがよわくなる\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>～に伴って</td><td>एक बदलाव दूसरे को साथ लाता है/जन्म देता है, अक्सर बड़े स्तर पर</td><td>じんこうのぞうかにともなって、じゅうたくぶそくがしんこくかしている (jinkou no zouka ni tomonatte, juutaku busoku ga shinkokuka shiteiru — जनसंख्या वृद्धि के साथ-साथ, आवास की कमी और गंभीर होती जा रही है) <button class=\"speak-btn\" data-speak=\"じんこうのぞうかにともなって、じゅうたくぶそくがしんこくかしている\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>～に従って</td><td>किसी नियम/निर्देश का पालन करना, या धीरे-धीरे प्रगति</td><td>きそくにしたがってこうどうしてください (kisoku ni shitagatte koudou shite kudasai — कृपया नियमों के अनुसार आचरण करें) <button class=\"speak-btn\" data-speak=\"きそくにしたがってこうどうしてください\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ये कहाँ अलग होते हैं</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>पूरी तरह धीमे, समानांतर बदलाव के लिए, तीनों अक्सर एक-दूसरे की जगह इस्तेमाल हो सकते हैं: ぶっかがあがるにつれて、せいかつがくるしくなる (bukka ga agaru ni tsurete, seikatsu ga kurushiku naru — जैसे-जैसे कीमतें बढ़ती हैं, जीवन कठिन होता जाता है) — यहाँ に伴って या に従って भी बहुत कम अर्थ-भेद के साथ काम कर जाएंगे।</li>\n                                        <li>केवल に伴って स्वाभाविक रूप से ऐसी घटना-संज्ञाओं से जुड़ता है जो साथ आने वाले नतीजे को बताती हैं: たいふうのせっきんにともなって、でんしゃがとまった (taifuu no sekkin ni tomonatte, densha ga tomatta — तूफ़ान के नज़दीक आने के साथ, ट्रेनें रुक गईं) <button class=\"speak-btn\" data-speak=\"たいふうのせっきんにともなって、でんしゃがとまった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>केवल に従って स्वाभाविक रूप से किसी नियम, आदेश या निर्देश के \"अनुसार\" चलने के अर्थ तक भी फैलता है — सिर्फ़ धीमे बदलाव तक सीमित नहीं।</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट एरिना</a> में सही सहसंबंधित-बदलाव पैटर्न मिलाएं, फिर <a href=\"#\" data-goto-tab=\"bridge\">ग्रामर ब्रिज</a> पर बारीकियों के नोट्स दोहराएं।</p>\n                                </div>\n                            </div>","day-pane-28":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-newspaper\" style=\"color: var(--accent-pink);\"></i> N2·7: लिखित जापानी\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>औपचारिक लिखित जापानी — अख़बार, रिपोर्ट, शोध-पत्र — में विनम्र です／ます शैली की जगह सादा・である शैली इस्तेमाल होती है, और कुछ ऐसे व्याकरण पैटर्न पर निर्भर करती है जो बोलचाल में शायद ही सुनने को मिलते हैं।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. である शैली — लिखित-रिपोर्ट का लहज़ा</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>बोलचाल/विनम्र अंत</th><th>लिखित (である) रूप</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>だ／です</td><td>である — これはもんだいである (kore wa mondai de aru — यह एक समस्या है) <button class=\"speak-btn\" data-speak=\"これはもんだいである\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>だった</td><td>であった</td></tr>\n                                            <tr><td>ではない／じゃない</td><td>ではない (अपरिवर्तित — सिर्फ़ सकारात्मक कॉपुला बदलता है)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top:8px;font-size:0.85rem;color:var(--text-muted);\">である शैली में भी क्रिया और विशेषण सामान्य रूप में ही रहते हैं (たべる、たかい) — सिर्फ़ कॉपुला बदलता है। एक ही लेख में です・ます और である को कभी न मिलाएं।</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. により और における — कारण और संदर्भ, औपचारिक रूप से</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>～により (によって／で का औपचारिक रूप) किसी कारण, माध्यम या तरीक़े को दर्शाता है: たいふうにより、おおくのいえがこわれた (taifuu ni yori, ooku no ie ga kowareta — तूफ़ान के कारण, कई घर तबाह हो गए) <button class=\"speak-btn\" data-speak=\"たいふうにより、おおくのいえがこわれた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>～における (での／においての का औपचारिक रूप) किसी बयान के लागू होने वाले समय, स्थान या क्षेत्र को बताता है, और सीधे संज्ञा से जुड़ता है: にほんにおけるしょうしかもんだい (nihon ni okeru shoushika mondai — जापान में जन्म-दर घटने की समस्या)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. をめぐって — के बारे में / को लेकर (किसी विवाद में)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>संज्ञा + をめぐって का मतलब है किसी विवादित विषय \"के बारे में/को लेकर\" — लगभग हमेशा किसी विवाद, चर्चा या बहस के साथ इस्तेमाल होता है।</li>\n                                        <li>あたらしいほうりつをめぐって、はげしいぎろんがつづいている (atarashii houritsu o megutte, hageshii giron ga tsuzuiteiru — नए क़ानून को लेकर तीखी बहस जारी है) <button class=\"speak-btn\" data-speak=\"あたらしいほうりつをめぐって、はげしいぎろんがつづいている\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"bridge\">ग्रामर ब्रिज</a> में लिखित-शैली का व्याकरण पहचानें, फिर <a href=\"#\" data-goto-tab=\"flashcards\">फ़्लैशकार्ड्स</a> से ख़ुद को परखें।</p>\n                                </div>\n                            </div>","day-pane-29":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-briefcase\" style=\"color: var(--accent-pink);\"></i> N2·8: केईगो II — व्यावसायिक शैली\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>व्यावसायिक केईगो, N3 के सम्मानसूचक/विनम्र मूल आधार पर एक और नियम जोड़ता है: <strong>内・外 (uchi・soto)</strong>। किसी बाहरी ग्राहक से बात करते समय, आपके अपने बॉस और सहकर्मी \"आपका पक्ष\" (内) बन जाते हैं — उनकी क्रियाओं का वर्णन विनम्र (humble) भाषा में करें, सम्मानसूचक भाषा में कभी नहीं, भले ही उसी बॉस से सीधे बात करते समय आप सम्मानसूचक भाषा इस्तेमाल करते हों।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. 内 (uchi) बनाम 外 (soto) — किसे सम्मान मिलता है</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>किसी सहकर्मी से, कंपनी के अंदर: ぶちょうはもういらっしゃいました (buchou wa mou irasshaimashita — मैनेजर पहले ही आ चुके हैं) — सम्मानसूचक, क्योंकि यहाँ सब \"अंदर\" के लोग हैं। <button class=\"speak-btn\" data-speak=\"ぶちょうはもういらっしゃいました\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>किसी बाहरी ग्राहक से, उसी मैनेजर के बारे में: ぶちょうはもうまいりました (buchou wa mou mairimashita — मैनेजर पहले ही आ चुके हैं) — विनम्र (humble), क्योंकि ग्राहक की नज़र में आपका मैनेजर अब \"आपका पक्ष\" है; कंपनी के अंदर का पद अब मायने नहीं रखता। <button class=\"speak-btn\" data-speak=\"ぶちょうはもうまいりました\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>यह उलटफेर सीखने वालों को किसी भी अकेले क्रिया-रूप से ज़्यादा उलझाता है — यह नियम सुनने वाले पर आधारित है, न कि जिसकी बात हो रही है उस पर।</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ございます, おる, まいる — व्यावसायिक-औपचारिक समूह</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>です → でございます: こちらがしりょうでございます (kochira ga shiryou de gozaimasu — यह रहा सामग्री/दस्तावेज़)</li>\n                                        <li>ある → ございます: おてあらいはあちらにございます (otearai wa achira ni gozaimasu — शौचालय उधर है)</li>\n                                        <li>いる → おる (विनम्र, अपने पक्ष के लिए): たなかはただいまがいしゅつしております (Tanaka wa tadaima gaishutsu shite orimasu — तानाका अभी दफ़्तर से बाहर हैं)</li>\n                                        <li>いく／くる → まいる (विनम्र, अपने पक्ष के लिए): すぐにまいります (sugu ni mairimasu — मैं अभी आता/आती हूँ)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. お／ご + stem + します — \"मैं आपके लिए यह करता/करती हूँ\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>お + क्रिया की ます-stem + します (या कई する-क्रियाओं के लिए ご + verbal noun + します) सुनने वाले के लिए कुछ करने की विनम्र पेशकश करता है। ध्यान दें कि जब ます-stem भी お से शुरू होती है तो सम्मानसूचक お दोहराया जाता है: おくる → おくり → <span class=\"ja-word\">おおくりします</span> (okuru → okuri → o okuri shimasu — मैं आपको यह भेज दूँगा/दूँगी), न कि おくりします।</li>\n                                        <li>ごれんらくします (go renraku shimasu — मैं आपसे संपर्क करूँगा/करूँगी) <button class=\"speak-btn\" data-speak=\"ごれんらくします\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>फ़ोन/ईमेल के मानक शुरुआती और समापन वाक्य: いつもおせわになっております (itsumo osewa ni natte orimasu — हमेशा आपके सहयोग के लिए धन्यवाद); よろしくおねがいいたします (yoroshiku onegai itashimasu — आपके सहयोग के लिए अग्रिम धन्यवाद) <button class=\"speak-btn\" data-speak=\"いつもおせわになっております。よろしくおねがいいたします\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट एरिना</a> में uchi/soto के बदलाव का अभ्यास करें, <a href=\"#\" data-goto-tab=\"builder\">सेंटेंस बिल्डर</a> में अपने ख़ुद के व्यावसायिक वाक्यांश बनाएं, फिर <a href=\"#\" data-goto-tab=\"bridge\">ग्रामर ब्रिज</a> पर पूरा सेट दोहराएं।</p>\n                                </div>\n                            </div>","day-pane-30":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-scroll\" style=\"color: var(--accent-pink);\"></i> N1·1: साहित्यिक निषेध (Literary Negatives) — ～んがため, ～ずして, ～べからず\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>N1 स्तर के पाठ आज भी उस शास्त्रीय (classical) व्याकरण पर निर्भर करते हैं, जो अब केवल रूढ़ वाक्यांशों, कहावतों और औपचारिक लेखन में ही बचा है। ये तीनों प्रयोग शास्त्रीय जापानी के निषेधात्मक (negative) या सहायक (auxiliary) रूपों से निकले हैं — इन्हें पहचानना आपके लिए आदर्श-वाक्यों, सूचना-पट्टों और साहित्यिक गद्य के द्वार खोल देता है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～んがため(に) — \"…के लिए\" (उद्देश्य बताने का प्राचीन रूप)</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>रूप</th><th>नियम</th><th>उदाहरण</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>सामान्य क्रियाएँ</td><td>ない-रूप बनाएं, फिर ない हटाकर + んがために जोड़ें</td><td>生きる → 生きない → <span class=\"ja-word\">生きんがために</span> (ikiru → ikinai → ikin ga tame ni — जीने के लिए)</td></tr>\n                                            <tr><td>する (अनियमित क्रिया)</td><td>せんがために बनता है, कभी しんがために नहीं</td><td>合格する → <span class=\"ja-word\">合格せんがために</span> (goukaku suru → goukaku sen ga tame ni — [परीक्षा] पास करने के लिए)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top:8px;font-size:0.85rem;color:var(--text-muted);\">प्रसिद्ध पंक्ति: 人は生きんがために食う (hito wa ikin ga tame ni kuu — मनुष्य जीने के लिए खाता है) — यह उस आम कहावत \"खाने के लिए जीना\" का उल्टा है।</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～ずして — \"…किए बिना\" (औपचारिक ～ないで)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>ない-रूप बनाएं, ない हटाकर + ずして जोड़ें — する का रूप せずして बनता है, कभी しずして नहीं।</li>\n                                        <li>努力せずして成功はあり得ない (doryoku sezu shite seikou wa arienai — बिना प्रयास के सफलता संभव नहीं) <button class=\"speak-btn\" data-speak=\"努力せずして成功はあり得ない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>यह अक्सर अलंकारिक प्रश्नों (rhetorical questions) में \"～ずして何であろうか\" (sezu shite nan de arou ka — अगर यह ~ नहीं है, तो और क्या है?) के रूप में इस्तेमाल होता है, जो किसी विकल्प को नकार कर बात की दृढ़ता से पुष्टि करता है।</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～べからず — \"मना है\" (औपचारिक निषेध)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>शब्दकोश रूप (dictionary form) + べからず — यह べし (करना ही चाहिए) का निषेधात्मक रूप है; する का रूप すべからず बनता है, जो इसका एकमात्र आम अनियमित अपवाद है।</li>\n                                        <li>芝生に入るべからず (shibafu ni hairu bekarazu — घास के मैदान में प्रवेश न करें) <button class=\"speak-btn\" data-speak=\"芝生に入るべからず\"><i class=\"fa-solid fa-volume-high\"></i></button> — यह पुराने सूचना-पट्टों और नोटिसों पर मिलने वाला परंपरागत वाक्य है।</li>\n                                        <li>आजकल इसकी जगह सीधी सूचना 立入禁止 (प्रवेश निषेध) ज़्यादा प्रचलित है, लेकिन べからず अब भी ऐतिहासिक सूचना-पट्टों, आदर्श-वाक्यों और औपचारिक लेखन में ～べきではない के एक अधिक सशक्त, साहित्यिक विकल्प के रूप में मिलता है।</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>इन प्राचीन निषेधों को <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट अरीना</a> में पहचानें, फिर इनके पीछे छिपे शास्त्रीय सहायक रूपों को <a href=\"#\" data-goto-tab=\"bridge\">त्रिभाषी सेतु</a> पर जाकर जांचें।</p>\n                                </div>\n                            </div>","day-pane-31":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-scale-unbalanced\" style=\"color: var(--accent-pink);\"></i> N1·2: रियायती भाव (Concessive Nuance) — ～ものを, ～ながら(も), ～といえども\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>रियायती (concessive) व्याकरण एक तथ्य को स्वीकार करते हुए ऐसी बात कहता है जो उससे विपरीत जान पड़ती है — यानी \"X के बावजूद भी, Y।\" ये तीनों प्रयोग अलग-अलग भाव जोड़ते हैं: पछतावा (regret), शांत विरोधाभास (quiet contrast), या औपचारिक तर्क (formal argument)।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～ものを — पछतावा: \"काश कि...\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>यह प्लेन-फ़ॉर्म (plain-form) उपवाक्य से जुड़ता है, जो बताता है कि क्या होना चाहिए था — और फिर वक्ता की निराशा या पछतावे को अधूरा छोड़ देता है, क्योंकि हकीकत में कुछ और ही हुआ।</li>\n                                        <li>すぐに謝ればいいものを、彼は意地を張った (sugu ni ayamareba ii mono o, kare wa iji o hatta — उसे तुरंत माफ़ी मांग लेनी चाहिए थी, लेकिन उसने ज़िद पकड़ ली) <button class=\"speak-btn\" data-speak=\"すぐに謝ればいいものを、彼は意地を張った\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>अक्सर ものを के बाद वाला उपवाक्य पूरी तरह छोड़ दिया जाता है, जिससे पछतावा खुद-ब-खुद झलकता है: 早く言ってくれればよかったものを…(hayaku itte kurereba yokatta mono o… — काश तुमने मुझे जल्दी बता दिया होता…)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～ながら(も) — \"…होते हुए भी / …के बावजूद\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>い-adjective / な-adjective का स्टेम (बिना な के, जैसे 残念ながら) / संज्ञा (noun) / क्रिया का ます-स्टेम + ながら(も) — यह N4 वाले \"एक साथ हो रही क्रियाओं\" वाले ながら से अलग है; यहाँ यह एक ही कर्ता (subject) के भीतर मौजूद विरोधाभास को स्वीकार करता है।</li>\n                                        <li>狭いながらも、幸せな家庭を築いた (semai nagara mo, shiawase na katei o kizuita — छोटा होते हुए भी, [उन्होंने] एक सुखी घर बसाया) <button class=\"speak-btn\" data-speak=\"狭いながらも、幸せな家庭を築いた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>知っていながら、彼は黙っていた (shitte inagara, kare wa damatte ita — जानते हुए भी, वह चुप रहा)।</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～といえども — \"…फिर भी / …होते हुए भी\" (औपचारिक)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>संज्ञा (noun) / प्लेन-फ़ॉर्म + といえども — पहले किसी बात को पूरी तरह स्वीकार करता है, फिर ज़ोर देकर कहता है कि इससे कुछ भी नहीं बदलता; यह निबंधों, भाषणों और कानूनी शैली के तर्कों में आम है।</li>\n                                        <li>子供といえども、責任は免れない (kodomo to iedomo, sekinin wa manugarenai — बच्चा होते हुए भी, [वह] ज़िम्मेदारी से बच नहीं सकता) <button class=\"speak-btn\" data-speak=\"子供といえども、責任は免れない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>プロといえども、失敗することはある (puro to iedomo, shippai suru koto wa aru — पेशेवर लोग (professionals) भी कभी-कभी असफल हो जाते हैं)।</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>पछतावे को रियायती भाव से अलग पहचानना <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट अरीना</a> में सीखें, फिर तीनों रूपों का अभ्यास <a href=\"#\" data-goto-tab=\"flashcards\">फ्लैशकार्ड</a> से करें।</p>\n                                </div>\n                            </div>","day-pane-32":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-bolt\" style=\"color: var(--accent-pink);\"></i> N1·3: तात्कालिकता (Immediacy) — ～なり, ～や否や, ～そばから\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>यह कहने के तीन तरीके कि \"X होते ही Y हो जाता है\" — लेकिन इन्हें आपस में बदला नहीं जा सकता। なり और や否や एक बार होने वाले अप्रत्याशित क्षण का वर्णन करते हैं; जबकि そばから एक ऐसे थकाऊ चक्र का वर्णन करता है जो बार-बार दोहराया जाता है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～なり — \"…करते ही\" (एक बार होने वाली अप्रत्याशित प्रतिक्रिया)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>शब्दकोश रूप (dictionary form) + なり — दूसरी क्रिया पहली के लगभग तुरंत बाद होती है, और अक्सर अप्रत्याशित होती है; दोनों उपवाक्यों का कर्ता (subject) सामान्यतः एक ही व्यक्ति होता है।</li>\n                                        <li>彼は帰宅するなり、部屋に閉じこもった (kare wa kitaku suru nari, heya ni tojikomotta — घर पहुंचते ही, वह अपने कमरे में बंद हो गया) <button class=\"speak-btn\" data-speak=\"彼は帰宅するなり、部屋に閉じこもった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～や否や(やいなや) — \"…होते ही\" (साहित्यिक प्रयोग)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>शब्दकोश रूप + や否や — यह なり से अधिक साहित्यिक है और कथात्मक (narrative) लेखन में आम है; दोनों उपवाक्यों के कर्ता अलग-अलग भी हो सकते हैं।</li>\n                                        <li>ベルが鳴るや否や、生徒たちは教室を飛び出した (beru ga naru ya ina ya, seitotachi wa kyoushitsu o tobidashita — घंटी बजते ही, छात्र कक्षा से बाहर भाग निकले) <button class=\"speak-btn\" data-speak=\"ベルが鳴るや否や、生徒たちは教室を飛び出した\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～そばから — \"…करते ही फिर से...\" (दोहराया जाने वाला चक्र)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>शब्दकोश रूप / た-रूप + そばから — なり और や否や के विपरीत, यह एक दोहराए जाने वाले, अक्सर थका देने वाले पैटर्न का वर्णन करता है, जिसमें दूसरी क्रिया बार-बार पहली को बेअसर कर देती है।</li>\n                                        <li>片付けるそばから、子供が散らかす (katazukeru soba kara, kodomo ga chirakasu — मैं जैसे ही साफ़ करता हूं, बच्चे फिर से गंदा कर देते हैं) <button class=\"speak-btn\" data-speak=\"片付けるそばから、子供が散らかす\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>習ったそばから忘れてしまう (naratta soba kara wasurete shimau — मैं जितनी तेज़ी से सीखता हूं, उतनी ही तेज़ी से भूल जाता हूं)।</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>एक-बार होने वाली तात्कालिकता को दोहराए जाने वाले चक्रों से अलग पहचानना <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट अरीना</a> में सीखें, फिर अपने खुद के なり और そばから वाक्य <a href=\"#\" data-goto-tab=\"builder\">वाक्य निर्माता</a> में बनाएं।</p>\n                                </div>\n                            </div>","day-pane-33":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-landmark\" style=\"color: var(--accent-pink);\"></i> N1·4: औपचारिक परिस्थिति (Formal Circumstance) — ～ともなると, ～とあって, ～に至って\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>ये तीनों बताते हैं कि कैसे कोई विशेष स्तर, अवसर या चरम बिंदु अपने आस-पास सब कुछ बदल देता है — यह समाचार रिपोर्टों और औपचारिक टिप्पणियों में आम प्रयोग है।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～ともなると／～ともなれば — \"जब बात … के स्तर तक पहुंच जाए...\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>संज्ञा / क्रिया का शब्दकोश रूप + ともなると(なれば) — जब कोई विशेष स्तर, समय या दर्जा (status) पहुंच जाए, तो उससे संबंधित बातें स्वाभाविक रूप से पीछे-पीछे आती हैं।</li>\n                                        <li>大企業の社長ともなると、責任は非常に重い (dai kigyou no shachou tomo naru to, sekinin wa hijou ni omoi — जब कोई किसी बड़ी कंपनी का अध्यक्ष बन जाता है, तो ज़िम्मेदारी बेहद भारी हो जाती है) <button class=\"speak-btn\" data-speak=\"大企業の社長ともなると、責任は非常に重い\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>年末ともなれば、街は買い物客でにぎわう (nenmatsu tomo nareba, machi wa kaimonokyaku de nigiwau — जब साल का अंत आता है, तो सड़कें खरीदारों से गुलज़ार हो जाती हैं)।</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～とあって — \"चूंकि यह एक ख़ास … है\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>संज्ञा / प्लेन-फ़ॉर्म + とあって — पहले किसी विशेष परिस्थिति को बताता है, फिर उससे उपजी स्वाभाविक प्रतिक्रिया का वर्णन करता है; यह समाचार-शैली के लेखन में आम है।</li>\n                                        <li>連休とあって、高速道路はどこも渋滞している (renkyuu to atte, kousoku douro wa doko mo juutai shiteiru — चूंकि यह एक लंबी छुट्टी है, हाईवे हर जगह जाम हैं) <button class=\"speak-btn\" data-speak=\"連休とあって、高速道路はどこも渋滞している\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～に至って(いたって) — \"…की हद तक पहुंचने पर ही...\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>संज्ञा / क्रिया का शब्दकोश रूप + に至って — कोई बात तभी आख़िरकार समझ में आती है, तय होती है, या उस पर कार्रवाई होती है जब मामला किसी चरम बिंदु तक पहुंच चुका होता है — अक्सर इसमें \"बहुत देर हो चुकी\" का भाव छिपा होता है।</li>\n                                        <li>手術が必要な状態に至って、彼はやっと病院へ行った (shujutsu ga hitsuyou na joutai ni itatte, kare wa yatto byouin e itta — जब हालत ऑपरेशन की ज़रूरत तक पहुंच गई, तब कहीं जाकर वह अस्पताल गया) <button class=\"speak-btn\" data-speak=\"手術が必要な状態に至って、彼はやっと病院へ行った\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>संबंधित रूप: ～に至っては किसी बड़े समूह में से एक चरम उदाहरण को अलग से चर्चा के लिए चुनता है; ～に至るまで का अर्थ है \"…तक बिल्कुल\"।</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>इन औपचारिक-परिस्थिति वाले वाक्यों को पढ़ने का अभ्यास <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट अरीना</a> में करें, फिर बारीकियों की समीक्षा <a href=\"#\" data-goto-tab=\"bridge\">त्रिभाषी सेतु</a> पर करें।</p>\n                                </div>\n                            </div>","day-pane-34":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-fingerprint\" style=\"color: var(--accent-pink);\"></i> N1·5: स्वभाव और रूढ़ वाक्यांश (Character & Set Phrases) — ～きらいがある, ～ずにはおかない, ～を余儀なくされる\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>प्रवृत्तियों (tendencies) और विवश परिणामों (forced outcomes) को बताने के लिए तीन रूढ़ वाक्यांश — किसी व्यक्ति की नकारात्मक आदत, एक अवश्यंभावी भावनात्मक असर, और ऐसी परिस्थिति जिसे किसी ने नहीं चुना।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～きらいがある — \"…की प्रवृत्ति होना\" (नकारात्मक)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>क्रिया का शब्दकोश रूप + きらいがある, या संज्ञा + の + きらいがある — यह किसी अंतर्निहित, प्रायः अवांछनीय प्रवृत्ति या बुरी आदत का वर्णन करता है, न कि किसी एक बार की घटना का।</li>\n                                        <li>彼は仕事を先延ばしにするきらいがある (kare wa shigoto o sakinobashi ni suru kirai ga aru — उसकी काम को टालते रहने की प्रवृत्ति है) <button class=\"speak-btn\" data-speak=\"彼は仕事を先延ばしにするきらいがある\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～ないではおかない／～ずにはおかない — \"…किए बिना नहीं रहता / …करके ही रहता है\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>ない-रूप + ではおかない, या ない-रूप (ない हटाकर) + ずにはおかない — कोई स्वाभाविक शक्ति या प्रबल भावना किसी असर को अवश्यंभावी बना देती है; यह दोहरा निषेध (double negative) असल में एक ज़ोरदार सकारात्मक भाव व्यक्त करता है।</li>\n                                        <li>この映画は観客を感動させないではおかない (kono eiga wa kankyaku o kandou sasenai de wa okanai — यह फ़िल्म दर्शकों को भावुक किए बिना नहीं रहेगी) <button class=\"speak-btn\" data-speak=\"この映画は観客を感動させないではおかない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>彼の行動は皆を怒らせずにはおかない (kare no koudou wa mina o okorasezu niwa okanai — उसका व्यवहार सबको ग़ुस्सा दिलाए बिना नहीं रहता)।</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～を余儀なくされる(よぎなくされる) — \"…करने को मजबूर होना\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>संज्ञा (अक्सर क्रिया से बनाई गई संज्ञा) + を余儀なくされる — किसी के भी नियंत्रण से बाहर की परिस्थितियां एक अवांछित परिणाम को मजबूर कर देती हैं; यह एक औपचारिक, कर्मवाच्य-जैसा (passive-feeling) प्रयोग है, जो समाचार रिपोर्टों में आम है।</li>\n                                        <li>台風のため、試合は中止を余儀なくされた (taifuu no tame, shiai wa chuushi o yoginaku sareta — तूफ़ान के कारण, मैच रद्द करने को मजबूर होना पड़ा) <button class=\"speak-btn\" data-speak=\"台風のため、試合は中止を余儀なくされた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>विवश परिणामों और नकारात्मक प्रवृत्तियों को <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट अरीना</a> में पहचानें, फिर तीनों पर ख़ुद को <a href=\"#\" data-goto-tab=\"flashcards\">फ्लैशकार्ड</a> से परखें।</p>\n                                </div>\n                            </div>","day-pane-35":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-newspaper\" style=\"color: var(--accent-pink);\"></i> N1·6: संपादकीय पढ़ना (Reading the Editorial)\n                                    <span class=\"badge\">व्याकरण</span>\n                                </div>\n                                <p>N1 स्तर की पठन-बोध (reading comprehension) परीक्षा काफ़ी हद तक 論説文 (ronsetsubun) — यानी विचारात्मक निबंधों और अख़बारी संपादकीयों पर आधारित होती है। इनके रूढ़ वाक्यांशों (stock phrases) और संयोजकों (connectors) को जान लेने से औपचारिक पाठ की एक दीवार भी एक पूर्वानुमेय तर्क-संरचना में बदल जाती है। इस पाठ के अंत में केइगो (keigo) से जुड़े दो आम भ्रम भी शामिल हैं।</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. संपादकीय के रूढ़ वाक्यांश (論説文の決まり文句)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>～と言わざるを得ない</strong> (to iwazaru o enai — कहे/माने बिना नहीं रहा जा सकता कि): この結果は失敗だったと言わざるを得ない (kono kekka wa shippai datta to iwazaru o enai — यह मानना ही पड़ेगा कि यह परिणाम एक असफलता थी) <button class=\"speak-btn\" data-speak=\"この結果は失敗だったと言わざるを得ない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong>～ではなかろうか</strong> (de wa nakarou ka — क्या यह … नहीं है?): यह किसी राय को अलंकारिक प्रश्न के रूप में, नरम और औपचारिक ढंग से रखने का तरीका है। それは杞憂ではなかろうか (sore wa kiyuu de wa nakarou ka — क्या यह शायद एक बेवजह की चिंता नहीं है?)</li>\n                                        <li><strong>～に他ならない</strong> (ni hoka naranai — और कुछ नहीं बल्कि …ही है): 彼の成功は努力の賜物に他ならない (kare no seikou wa doryoku no tamamono ni hoka naranai — उसकी सफलता और कुछ नहीं बल्कि परिश्रम का फल है) <button class=\"speak-btn\" data-speak=\"彼の成功は努力の賜物に他ならない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. औपचारिक संयोजक (connectors) — したがって, もっとも, ゆえに</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>したがって</strong> (shitagatte — अतः, इसलिए): पहले कही गई बात से तार्किक रूप से निकाले गए निष्कर्ष को जोड़ता है; यह だから से अधिक औपचारिक है।</li>\n                                        <li><strong>もっとも</strong> (mottomo — फिर भी, हालांकि): किसी दावे के बाद उसमें एक शर्त या अपवाद जोड़ता है, जिससे अभी कही गई बात थोड़ी नरम पड़ जाती है।</li>\n                                        <li><strong>ゆえに</strong> (yueni — अतः, इसलिए): तीनों में सबसे अधिक औपचारिक/तार्किक, जो शैक्षणिक और कानूनी लेखन में आम है; अक्सर इससे पहले それ लगाया जाता है (それゆえに)।</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. केइगो (keigo) के दो आम भ्रम</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>二重敬語 (दोहरा केइगो):</strong> おっしゃられる ग़लत है — यह पहले से ही आदरसूचक (honorific) おっしゃる (कहना) के ऊपर आदरसूचक प्रत्यय ～られる जोड़ देता है। सिर्फ़ おっしゃる कहें, या फिर 言われる।</li>\n                                        <li><strong>伺う बनाम 参る</strong> (दोनों विनम्र (humble) रूप में \"जाना/आना\" के अर्थ में हैं, पर एक-दूसरे की जगह इस्तेमाल नहीं होते): 伺う (ukagau) का अर्थ है किसी ऊंचे दर्जे के व्यक्ति से मिलने, पूछने या सुनने के लिए जाना — यह दूसरे पक्ष की ओर निर्दिष्ट (directed) होता है। वहीं 参る (mairu) एक सामान्य विनम्र \"जाना/आना\" है, जिसमें ऐसी कोई दिशा-सूचकता नहीं होती, और यह सामान्य व्यावसायिक प्रयोग के लिए ठीक रहता है: 今参ります (ima mairimasu — मैं अभी आ रहा हूं)।</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> जो सीखा उसका अभ्यास करें</div>\n                                    <p>इन संपादकीय प्रयोगों को पहचानने का अभ्यास <a href=\"#\" data-goto-tab=\"arena\">क्वेस्ट अरीना</a> में करें, फिर पूरी केइगो सीढ़ी (keigo ladder) की समीक्षा <a href=\"#\" data-goto-tab=\"bridge\">त्रिभाषी सेतु</a> पर करें।</p>\n                                </div>\n                            </div>"};
